import React, { useState, useCallback, useEffect, useRef } from 'react';
import { useClaudeAPI } from '../hooks/useClaudeAPI';
import { useTheme } from '../hooks/useTheme';
import { usePersistentState } from '../hooks/usePersistentState';
import { useRegisterActions } from '../components/ActionBarContext';

const BRAND = '\n\n— Generated by DeftBrain · deftbrain.com';

const CATEGORIES = {
  quick_hit: { emoji: '⚡', label: 'Quick Hit', color: 'amber' },
  medium_recharge: { emoji: '🔋', label: 'Medium Recharge', color: 'emerald' },
  deep_reset: { emoji: '🌊', label: 'Deep Reset', color: 'cyan' },
  social: { emoji: '👥', label: 'Social', color: 'emerald' },
  physical: { emoji: '🏃', label: 'Physical', color: 'amber' },
  creative: { emoji: '🎨', label: 'Creative', color: 'amber' },
  sensory: { emoji: '🌿', label: 'Sensory', color: 'emerald' },
};
const ENERGY_LABELS = ['', 'Crashed', 'Wiped', 'Drained', 'Low', 'Meh', 'Okay', 'Decent', 'Good', 'Great', 'Fired up'];
const ENERGY_EMOJIS = ['', '😵', '😩', '😮‍💨', '😐', '🫤', '🙂', '😊', '😄', '🤩', '🔥'];
const QUICK_STATES = [
  { energy: 2, time: '15 minutes', context: 'Totally drained', label: '😵 Crashed', mood: 'numb' },
  { energy: 4, time: '30 minutes', context: 'Low energy', label: '😐 Low battery', mood: '' },
  { energy: 5, time: '1 hour', context: 'Bored and restless', label: '🫤 Blah', mood: 'bored' },
  { energy: 7, time: '2 hours', context: 'Good energy', label: '😊 Ready', mood: '' },
];
const TIME_OPTS = [{ v: '5 minutes', l: '5m' }, { v: '15 minutes', l: '15m' }, { v: '30 minutes', l: '30m' }, { v: '1 hour', l: '1hr' }, { v: '2 hours', l: '2hr' }, { v: 'All evening', l: 'Evening' }];
const MOOD_OPTS = [{ v: 'stressed', l: '😤 Stressed' }, { v: 'sad', l: '😢 Sad' }, { v: 'anxious', l: '😰 Anxious' }, { v: 'restless', l: '🫠 Restless' }, { v: 'overstimulated', l: '🤯 Overstimulated' }, { v: 'bored', l: '😑 Bored' }, { v: 'numb', l: '😶 Numb' }];
const ENV_OPTS = [{ v: 'home', l: '🏠 Home' }, { v: 'office', l: '🏢 Office' }, { v: 'commuting', l: '🚌 Commuting' }, { v: 'outdoors', l: '🌳 Outdoors' }, { v: 'in_bed', l: '🛏️ In Bed' }];
const CHECKIN_OPTS = [{ v: 30, l: '30m' }, { v: 60, l: '1hr' }, { v: 90, l: '1.5hr' }, { v: 120, l: '2hr' }];
const DEBT_COLORS = { none: 'ok', mild: 'warn', moderate: 'warn', severe: 'bad' };

const MODES = [
  { id: 'recharge', icon: '✨', label: 'Suggest' },
  { id: 'budget', icon: '🥄', label: 'Budget' },
  { id: 'forecast', icon: '🔋', label: 'Forecast' },
  { id: 'radar', icon: '📡', label: 'Radar' },
  { id: 'disruption', icon: '🔄', label: 'Disruption' },
];

const RADAR_STATUS = {
  green: { icon: '🟢', color: 'ok', label: 'All clear' },
  yellow: { icon: '🟡', color: 'warn', label: 'Worth watching' },
  orange: { icon: '🟠', color: 'warn', label: 'Early warning' },
  red: { icon: '🔴', color: 'bad', label: 'Burnout approaching' },
};

const DISRUPTION_TYPES = [
  { v: 'sick_day', l: '🤒 Sick day' },
  { v: 'travel', l: '✈️ Travel' },
  { v: 'schedule_change', l: '📅 Schedule change' },
  { v: 'emergency', l: '🚨 Emergency' },
  { v: 'mental_health', l: '🧠 Tough day' },
  { v: 'life_event', l: '🌊 Life event' },
];

const PRIORITY_OPTS = [
  { v: 'required', l: '🔴 Required', desc: 'Must happen today' },
  { v: 'important', l: '🟡 Important', desc: 'Should happen' },
  { v: 'optional', l: '🟢 Optional', desc: 'Nice if possible' },
];

const EVENT_TYPES = [
  { v: 'work_meeting', l: '💼 Work meeting' }, { v: 'social', l: '🎉 Social' },
  { v: 'family', l: '👨‍👩‍👧 Family' }, { v: 'networking', l: '🤝 Networking' },
  { v: '1on1', l: '☕ 1-on-1' }, { v: 'presentation', l: '🎤 Presenting' },
];

function getTimeOfDay() { const h = new Date().getHours(); if (h < 8) return 'early_morning'; if (h < 11) return 'morning'; if (h < 14) return 'midday'; if (h < 17) return 'afternoon'; if (h < 20) return 'evening'; return 'night'; }
function getTimeOfDayLabel(tod) { return { early_morning: '🌅 Early morning', morning: '☀️ Morning', midday: '🌤️ Midday', afternoon: '🌇 Afternoon', evening: '🌆 Evening', night: '🌙 Night' }[tod] || tod; }

const PEP = ({ tool }) => {
  const { callToolEndpoint, loading } = useClaudeAPI();
  const { isDark } = useTheme();

  const c = {
    card:          isDark ? 'bg-zinc-800' : 'bg-white',
    cardAlt:       isDark ? 'bg-zinc-700/50' : 'bg-slate-50',
    text:          isDark ? 'text-zinc-50' : 'text-gray-900',
    textSecondary: isDark ? 'text-zinc-300' : 'text-gray-600',
    textMuted:     isDark ? 'text-zinc-500' : 'text-gray-400',
    input:         isDark ? 'bg-zinc-700 border-zinc-600 text-zinc-100 placeholder-zinc-400 focus:ring-cyan-500' : 'bg-white border-gray-300 text-gray-900 placeholder-gray-400 focus:ring-cyan-500',
    btnPrimary:    isDark ? 'bg-cyan-600 hover:bg-cyan-500 text-white' : 'bg-cyan-600 hover:bg-cyan-700 text-white',
    btnSecondary:  isDark ? 'bg-zinc-700 hover:bg-zinc-600 text-zinc-100' : 'bg-gray-100 hover:bg-gray-200 text-gray-700',
    border:        isDark ? 'border-zinc-700' : 'border-gray-200',
    success:       isDark ? 'bg-emerald-900/20 border-emerald-700 text-emerald-200' : 'bg-emerald-50 border-emerald-300 text-emerald-800',
    warning:       isDark ? 'bg-amber-900/20 border-amber-700 text-amber-200' : 'bg-amber-50 border-amber-300 text-amber-800',
    danger:        isDark ? 'bg-red-900/20 border-red-700 text-red-200' : 'bg-red-50 border-red-200 text-red-800',
    highlight:     isDark ? 'bg-cyan-900/20 border-cyan-700 text-cyan-200' : 'bg-cyan-50 border-cyan-200 text-cyan-800',
    subtle:        isDark ? 'bg-zinc-700/40 border-zinc-600 text-zinc-300' : 'bg-slate-100 border-slate-200 text-slate-700',
    timer:         isDark ? 'bg-emerald-900/20 border-emerald-700 text-emerald-200' : 'bg-emerald-50 border-emerald-300 text-emerald-800',
    labelText:     isDark ? 'text-zinc-200' : 'text-gray-700',
    accentTxt:     isDark ? 'text-cyan-400' : 'text-cyan-600',
    infoBox:       isDark ? 'bg-sky-900/20 border-sky-700 text-sky-200' : 'bg-sky-50 border-sky-200 text-sky-800',
    successBox:    isDark ? 'bg-emerald-900/20 border-emerald-700' : 'bg-emerald-50 border-emerald-300',
    successTxt:    isDark ? 'text-emerald-300' : 'text-emerald-800',
    warningBox:    isDark ? 'bg-amber-900/20 border-amber-700' : 'bg-amber-50 border-amber-300',
    warningTxt:    isDark ? 'text-amber-300' : 'text-amber-800',
    pillActive:    isDark ? 'border-cyan-500 bg-cyan-900/30 text-cyan-200' : 'border-cyan-600 bg-cyan-100 text-cyan-900',
    pillInactive:  isDark ? 'border-zinc-600 text-zinc-400 hover:border-zinc-500' : 'border-gray-300 text-gray-500 hover:border-gray-400',
    required:      isDark ? 'text-amber-400' : 'text-amber-500',
    deleteHover:   isDark ? 'hover:text-red-400' : 'hover:text-red-600',
  };
  c.textMuteded = c.textMuted;
  c.label = c.labelText;

  const chip = (a) => a
    ? (isDark ? 'bg-emerald-900/40 border-emerald-500 text-emerald-200' : 'bg-emerald-100 border-emerald-400 text-emerald-800')
    : (isDark ? 'border-zinc-600 text-zinc-400 hover:border-zinc-500' : 'border-gray-200 text-gray-500 hover:border-gray-300');

  const linkStyle = isDark
    ? 'text-cyan-400 hover:text-cyan-300 underline underline-offset-2'
    : 'text-cyan-600 hover:text-cyan-700 underline underline-offset-2';

  const catInfo = (cat) => CATEGORIES[cat] || CATEGORIES.quick_hit;

  // ─── State ───
  const [timeAvail, setTimeAvail] = useState('');
  const [recentActs, setRecentActs] = useState('');
  const [context, setContext] = useState('');
  const [mood, setMood] = useState('');
  const [environment, setEnvironment] = useState('');
  const [swapResult, setSwapResult] = useState(null);
  const [swapLoading, setSwapLoading] = useState(false);
  const [sessionSuggestions, setSessionSuggestions] = useState([]);
  const [showMyMenu, setShowMyMenu] = useState(false);
  const [showPartnerMenu, setShowPartnerMenu] = useState(false);
  const [buildMenuResult, setBuildMenuResult] = useState(null);
  const [buildMenuLoading, setBuildMenuLoading] = useState(false);
  const [buildInterests, setBuildInterests] = useState('');
  const [matchResult, setMatchResult] = useState(null);
  const [matchLoading, setMatchLoading] = useState(false);
  const [ratingActivity, setRatingActivity] = useState(null);
  const [rateScore, setRateScore] = useState(7);
  const [energyAfter, setEnergyAfter] = useState(6);
  const [rateNote, setRateNote] = useState('');
  const [rateAnchor, setRateAnchor] = useState('');
  const [rateResult, setRateResult] = useState(null);
  const [rateLoading, setRateLoading] = useState(false);
  const [nudgeResult, setNudgeResult] = useState(null);
  const [nudgeLoading, setNudgeLoading] = useState(false);
  const [seqResult, setSeqResult] = useState(null);
  const [seqLoading, setSeqLoading] = useState(false);
  const [seqStep, setSeqStep] = useState(0);
  const [showCheckin, setShowCheckin] = useState(false);
  const [checkinMinutes, setCheckinMinutes] = useState(60);
  const [checkinResult, setCheckinResult] = useState(null);
  const [checkinLoading, setCheckinLoading] = useState(false);
  const [checkinTimer, setCheckinTimer] = useState(null);
  const [checkinRemaining, setCheckinRemaining] = useState(null);
  const [patternResult, setPatternResult] = useState(null);
  const [patternLoading, setPatternLoading] = useState(false);
  const [insightsResult, setInsightsResult] = useState(null);
  const [insightsLoading, setInsightsLoading] = useState(false);
  // v5
  const [justDoResult, setJustDoResult] = useState(null);
  const [justDoLoading, setJustDoLoading] = useState(false);
  const [debtResult, setDebtResult] = useState(null);
  const [debtLoading, setDebtLoading] = useState(false);
  const [surpriseActivity, setSurpriseActivity] = useState(null);
  const [surpriseLock, setSurpriseLock] = useState(null);
  const [surpriseRemaining, setSurpriseRemaining] = useState(null);
  const surpriseRef = useRef(null);
  const resultsRef = useRef(null);

  const [showSavedSeqs, setShowSavedSeqs] = useState(false);
  const [showEnergyChart, setShowEnergyChart] = useState(false);

  // ─── Mode (v6) ───
  const [mode, setMode] = useState('recharge');

  // ─── Budget mode state ───
  const [budgetTasks, setBudgetTasks] = useState([{ task: '', cost: 3, priority: 'required' }]);
  const [budgetResult, setBudgetResult] = useState(null);

  // ─── Forecast mode state ───
  const [forecastEvents, setForecastEvents] = useState([]);
  const [energyType, setEnergyType] = useState(40);
  const [currentBattery, setCurrentBattery] = useState(80);
  const [rechargeHours, setRechargeHours] = useState(3);
  const [forecastResult, setForecastResult] = useState(null);
  const [declineTarget, setDeclineTarget] = useState(null);
  const [declineResult, setDeclineResult] = useState(null);

  // ─── Radar mode state ───
  const [radarSleep, setRadarSleep] = useState(3);
  const [radarMood, setRadarMood] = useState(3);
  const [radarProd, setRadarProd] = useState(3);
  const [radarSocial, setRadarSocial] = useState(3);
  const [radarSymptoms, setRadarSymptoms] = useState('');
  const [radarResult, setRadarResult] = useState(null);
  const [radarAnalysis, setRadarAnalysis] = useState(null);

  // ─── Disruption mode state ───
  const [disruptType, setDisruptType] = useState('');
  const [normalRoutine, setNormalRoutine] = useState('');
  const [constraints, setConstraints] = useState('');
  const [criticalTasks, setCriticalTasks] = useState('');
  const [disruptDuration, setDisruptDuration] = useState('');
  const [disruptResult, setDisruptResult] = useState(null);

  // ─── Persistent ───
  const [energy, setEnergy] = usePersistentState('pep-energy', 5);
  const [results, setResults] = usePersistentState('pep-results', null);
  const [myMenu, setMyMenu] = usePersistentState('pep-my-menu', []);
  const [partnerMenu, setPartnerMenu] = usePersistentState('pep-partner-menu', []);
  const [activityLog, setActivityLog] = usePersistentState('pep-log', []);
  const [savedSequences, setSavedSequences] = usePersistentState('pep-sequences', []);
  const [checkinLog, setCheckinLog] = usePersistentState('pep-radar-log', []);

  // ─── Timer refs (must precede the useEffects that use them) ───
  const timerRef = useRef(null);

  const budgetTasksInputRefs = useRef([]);
  const shouldFocusNewBudgetTasksRef = useRef(false);
  const forecastEventsInputRefs = useRef([]);
  const shouldFocusNewForecastEventsRef = useRef(false);
  // ─── Timers ───
  useEffect(() => {
    if (checkinTimer) {
      timerRef.current = setInterval(() => { const r = checkinTimer - Date.now(); if (r <= 0) { clearInterval(timerRef.current); setCheckinRemaining(0); setCheckinTimer(null); } else setCheckinRemaining(r); }, 1000);
      return () => clearInterval(timerRef.current);
    }
  }, [checkinTimer]);
  useEffect(() => {
    if (surpriseLock) {
      surpriseRef.current = setInterval(() => { const r = surpriseLock - Date.now(); if (r <= 0) { clearInterval(surpriseRef.current); setSurpriseRemaining(0); setSurpriseLock(null); } else setSurpriseRemaining(r); }, 1000);
      return () => clearInterval(surpriseRef.current);
    }
  }, [surpriseLock]);

  // ─── Helpers ───
  const addToMenu = (activity, category, effort, duration, eMin, eMax, envs, target) => {
    const setter = target === 'partner' ? setPartnerMenu : setMyMenu;
    setter(p => { if (p.find(a => a.name === activity)) return p; return [...p, { id: `dm_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`, name: activity, category: category || 'quick_hit', effort: effort || 'low', duration: duration || '?', energy_min: eMin || 1, energy_max: eMax || 10, environments: envs || [], avg_rating: null, use_count: 0, sensory_anchor: null, addedAt: new Date().toISOString() }]; });
  };
  const removeFromMenu = (id, target) => (target === 'partner' ? setPartnerMenu : setMyMenu)(p => p.filter(a => a.id !== id));

  const logActivity = useCallback((activity, category, rating, eBefore, eAfter, note, anchor) => {
    setActivityLog(p => [{ id: `al_${Date.now()}`, activity, category: category || '?', rating: rating || 0, energy_before: eBefore || energy, energy_after: eAfter || energy, mood: mood || '', note: note || '', sensory_anchor: anchor || '', date: new Date().toISOString() }, ...p].slice(0, 6));
    setMyMenu(p => p.map(a => {
      if (a.name === activity) {
        const nc = (a.use_count || 0) + 1;
        const ot = (a.avg_rating || 0) * (a.use_count || 0);
        return { ...a, use_count: nc, avg_rating: Math.round(((ot + (rating || 0)) / nc) * 10) / 10, sensory_anchor: anchor || a.sensory_anchor };
      }
      return a;
    }));
  }, [energy, mood, setActivityLog, setMyMenu]);

  const trackSuggestions = (res) => {
    const acts = [];
    if (res?.menu?.top_pick) acts.push(res.menu.top_pick.activity);
    ['quick_hits', 'medium_recharges', 'deep_resets'].forEach(k => (res?.menu?.[k] || []).forEach(a => acts.push(a.activity)));
    setSessionSuggestions(p => [...new Set([...p, ...acts])]);
  };

  const reset = () => {
    setResults(null); setSwapResult(null); setMatchResult(null); setSeqResult(null); setSeqStep(0);
    setRatingActivity(null); setRateResult(null); setNudgeResult(null);
    setShowCheckin(false); setCheckinResult(null); setJustDoResult(null);
    setSurpriseActivity(null); setSurpriseLock(null); setSurpriseRemaining(null);
  };

  const formatMs = (ms) => { if (!ms || ms <= 0) return '0:00'; const m = Math.floor(ms / 60000); const s = Math.floor((ms % 60000) / 1000); return `${m}:${String(s).padStart(2, '0')}`; };

  // ═══ API CALLS ═══
  const baseParams = () => ({ time_of_day: getTimeOfDay(), mood: mood || null, environment: environment || null, already_tried: sessionSuggestions.length ? sessionSuggestions : null, curated_menu: myMenu.length ? myMenu : null });

  const handleGenerate = async () => {
    reset();
    const d = await callToolEndpoint('pep', { action: 'generate', energy, time_available: timeAvail || null, recent_activities: recentActs.trim() || null, context: context.trim() || null, ...baseParams() });
    if (d) { setResults(d); trackSuggestions(d); setTimeout(() => resultsRef.current?.scrollIntoView({ behavior: 'smooth' }), 100); }
  };
  const handleQuickState = async (s) => {
    setEnergy(s.energy); setTimeAvail(s.time); setContext(s.context); if (s.mood) setMood(s.mood);
    reset();
    const d = await callToolEndpoint('pep', { action: 'generate', energy: s.energy, time_available: s.time, context: s.context, ...baseParams(), mood: s.mood || mood || null });
    if (d) { setResults(d); trackSuggestions(d); setTimeout(() => resultsRef.current?.scrollIntoView({ behavior: 'smooth' }), 100); }
  };
  const handleJustDo = async () => {
    setJustDoLoading(true); setJustDoResult(null);
    const d = await callToolEndpoint('pep', { action: 'just-do-this', energy, ...baseParams() });
    if (d) { setJustDoResult(d); setSessionSuggestions(p => [...new Set([...p, d.activity])]); }
    setJustDoLoading(false);
  };
  const handleSwap = async (rejected) => { setSwapLoading(true); const d = await callToolEndpoint('pep', { action: 'swap', rejected_activities: rejected, energy, time_available: timeAvail || null, mood: mood || null, environment: environment || null, already_tried: sessionSuggestions }); if (d) { setSwapResult(d); (d.alternatives || []).forEach(a => setSessionSuggestions(p => [...new Set([...p, a.activity])])); } setSwapLoading(false); };
  const handleEnergyMatch = async () => { if (!myMenu.length) return; setMatchLoading(true); const d = await callToolEndpoint('pep', { action: 'energy-match', energy, time_available: timeAvail || null, curated_menu: myMenu, mood: mood || null, environment: environment || null }); if (d) setMatchResult(d); setMatchLoading(false); };
  const handleBuildMenu = async (shared) => { setBuildMenuLoading(true); const d = await callToolEndpoint('pep', { action: 'build-menu', interests: buildInterests.trim() || null, existing_menu: (shared ? partnerMenu : myMenu).length ? (shared ? partnerMenu : myMenu) : null, environment: environment || null, shared: !!shared }); if (d) setBuildMenuResult(d); setBuildMenuLoading(false); };
  const handleRate = async () => {
    if (!ratingActivity) return; setRateLoading(true);
    const d = await callToolEndpoint('pep', { action: 'rate-activity', activity: ratingActivity.activity, rating: rateScore, energy_before: energy, energy_after: energyAfter, note: rateNote.trim() || null, sensory_anchor: rateAnchor.trim() || null, history: activityLog.slice(0, 6) });
    if (d) { setRateResult(d); logActivity(ratingActivity.activity, ratingActivity.category, rateScore, energy, energyAfter, rateNote, rateAnchor.trim()); }
    setRateLoading(false);
  };
  const handleNudge = async (act) => { setNudgeResult(null); setNudgeLoading(true); const d = await callToolEndpoint('pep', { action: 'accountability-nudge', activity: act }); if (d) setNudgeResult(d); setNudgeLoading(false); };
  const handleSequence = async () => { setSeqLoading(true); setSeqResult(null); setSeqStep(0); const d = await callToolEndpoint('pep', { action: 'build-sequence', energy, time_available: timeAvail || '30 minutes', mood: mood || null, environment: environment || 'home', curated_menu: myMenu.length ? myMenu : null }); if (d) setSeqResult(d); setSeqLoading(false); };
  const handleCheckin = async () => { setCheckinLoading(true); const d = await callToolEndpoint('pep', { action: 'schedule-checkin', checkin_time: `in ${checkinMinutes} minutes`, current_energy: energy, current_mood: mood || null, current_activity: recentActs.trim() || context.trim() || null, curated_menu: myMenu.length ? myMenu : null }); if (d) { setCheckinResult(d); setCheckinTimer(Date.now() + checkinMinutes * 60 * 1000); } setCheckinLoading(false); };
  const handlePatterns = async () => { if (activityLog.length < 3) return; setPatternLoading(true); const d = await callToolEndpoint('pep', { action: 'pattern-check', activity_log: activityLog.slice(0, 6) }); if (d) setPatternResult(d); setPatternLoading(false); };
  const handleInsights = async () => { if (activityLog.length < 5) return; setInsightsLoading(true); const d = await callToolEndpoint('pep', { action: 'recharge-insights', activity_log: activityLog.slice(0, 6), curated_menu: myMenu.length ? myMenu : null }); if (d) setInsightsResult(d); setInsightsLoading(false); };
  const handleDebtCheck = async () => { setDebtLoading(true); const recent = activityLog.slice(0, 6).map(a => a.energy_before); const d = await callToolEndpoint('pep', { action: 'debt-check', activity_log: activityLog.slice(0, 6), recent_energies: recent.length ? recent : [energy] }); if (d) setDebtResult(d); setDebtLoading(false); };

  // ═══ v6: NEW MODE API CALLS ═══

  // Budget
  const handleBudget = async () => {
    const filled = budgetTasks.filter(t => t.task.trim());
    if (!filled.length) return;
    setBudgetResult(null);
    const d = await callToolEndpoint('pep', { action: 'budget', tasks: filled, available_energy: energy, mood: mood || null });
    if (d) setBudgetResult(d);
  };
  const addBudgetTask = () => { shouldFocusNewBudgetTasksRef.current = true; setBudgetTasks(p => [...p, { task: '', cost: 3, priority: 'optional' }]); };
  const updateBudgetTask = (i, field, val) => setBudgetTasks(p => p.map((t, j) => j === i ? { ...t, [field]: val } : t));
  const removeBudgetTask = (i) => setBudgetTasks(p => p.filter((_, j) => j !== i));

  // Forecast
  const handleForecast = async () => {
    if (!forecastEvents.length) return;
    setForecastResult(null);
    const d = await callToolEndpoint('pep', { action: 'forecast', events: forecastEvents, energy_type: energyType, current_battery: currentBattery, recharge_hours: rechargeHours, activity_log: activityLog.slice(0, 6) });
    if (d) setForecastResult(d);
  };
  const addForecastEvent = () => { shouldFocusNewForecastEventsRef.current = true; setForecastEvents(p => [...p, { name: '', day: '', time: '', duration: '1 hour', people: '5', role: 'attending', canLeave: true, type: 'social' }]); };
  const updateForecastEvent = (i, field, val) => setForecastEvents(p => p.map((e, j) => j === i ? { ...e, [field]: val } : e));
  const removeForecastEvent = (i) => setForecastEvents(p => p.filter((_, j) => j !== i));
  const handleDecline = async (eventName) => {
    setDeclineResult(null); setDeclineTarget(eventName);
    const d = await callToolEndpoint('pep', { action: 'decline-message', event_name: eventName, reason: 'at capacity', relationship: 'friend' });
    if (d) setDeclineResult(d);
  };

  // Radar
  const handleRadarCheckin = async () => {
    setRadarResult(null);
    const d = await callToolEndpoint('pep', { action: 'radar-checkin', sleep: radarSleep, mood: radarMood, productivity: radarProd, social_energy: radarSocial, physical_symptoms: radarSymptoms.trim() || null, checkin_history: checkinLog.slice(0, 14) });
    if (d) {
      setRadarResult(d);
      setCheckinLog(prev => {
        const today = new Date().toISOString().split('T')[0];
        const entry = { date: new Date().toISOString(), sleep: radarSleep, mood: radarMood, productivity: radarProd, social_energy: radarSocial, physical_symptoms: radarSymptoms.trim() || null, status: d.status, preview: (d.status || 'check-in').slice(0, 40) };
        const filtered = prev.filter(e => e.date?.split('T')[0] !== today);
        return [entry, ...filtered].slice(0, 14);
      });
    }
  };
  const handleRadarAnalyze = async () => {
    if (checkinLog.length < 5) return;
    setRadarAnalysis(null);
    const d = await callToolEndpoint('pep', { action: 'radar-analyze', checkin_log: checkinLog.slice(0, 6) });
    if (d) setRadarAnalysis(d);
  };

  // Disruption
  const handleDisruption = async () => {
    if (!disruptType) return;
    setDisruptResult(null);
    const d = await callToolEndpoint('pep', { action: 'disruption', disruption_type: disruptType, normal_routine: normalRoutine.trim() || null, constraints: constraints.trim() || null, critical_tasks: criticalTasks.trim() || null, available_energy: energy, duration_estimate: disruptDuration.trim() || null });
    if (d) setDisruptResult(d);
  };

  // v5: Surprise Me
  const handleSurprise = () => {
    const pool = myMenu.filter(a => (a.avg_rating || 5) >= 5 && (a.energy_min || 1) <= energy && (a.energy_max || 10) >= energy);
    if (!pool.length) return;
    const pick = pool[Math.floor(Math.random() * pool.length)];
    setSurpriseActivity(pick); setSurpriseLock(Date.now() + 10 * 60 * 1000); setSurpriseRemaining(10 * 60 * 1000);
  };

  // v5: Save sequence
  const saveSequence = () => { if (!seqResult) return; setSavedSequences(p => [{ ...seqResult, id: `seq_${Date.now()}`, savedAt: new Date().toISOString() }, ...p].slice(0, 6)); };

  // ─── Copy text ───
  const buildText = useCallback(() => {
    if (!results) return '';
    const L = ['PEP — PERSONAL ENERGY PLANNER', '', results.energy_read || '', ''];
    const tp = results.menu?.top_pick; if (tp) { L.push(`⭐ TOP PICK: ${tp.activity}`); L.push(`   ${tp.why}`); L.push(''); }
    ['quick_hits', 'medium_recharges', 'deep_resets'].forEach(k => { const items = results.menu?.[k]; if (!items?.length) return; L.push(`${k.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}:`); items.forEach(a => L.push(`  • ${a.activity} (${a.duration})`)); L.push(''); });
    if (results.pleasure_vs_numbing) L.push(`💡 ${results.pleasure_vs_numbing}`);
    L.push(BRAND); return L.join('\n');
  }, [results]);

  // ── PF-8: useRegisterActions (after buildText, after all hooks) ──
  useRegisterActions(buildText(), tool?.title || 'PEP');

  // ── PF-6: Keyboard submit (refs pattern, after handleGenerate declaration) ──
  const handleGenerateRef = React.useRef(null);
  const canSubmitRef = React.useRef(false);
  handleGenerateRef.current = handleGenerate;
  canSubmitRef.current = !loading;

  React.useEffect(() => {
    const handler = (e) => {
      const tag = document.activeElement?.tagName;
      if (tag === 'SELECT') return;
      if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && canSubmitRef.current)
        handleGenerateRef.current?.();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (shouldFocusNewBudgetTasksRef.current) {
      const last = budgetTasksInputRefs.current[budgetTasks.length - 1];
      if (last) last.focus();
      shouldFocusNewBudgetTasksRef.current = false;
    }
  }, [budgetTasks.length]);

  useEffect(() => {
    if (shouldFocusNewForecastEventsRef.current) {
      const last = forecastEventsInputRefs.current[forecastEvents.length - 1];
      if (last) last.focus();
      shouldFocusNewForecastEventsRef.current = false;
    }
  }, [forecastEvents.length]);

  // ─── Shared UI ───
  const Pill = ({ options, value, setter }) => <div className="flex flex-wrap gap-1.5">{options.map(o => <button key={o.v} onClick={() => setter(value === o.v ? '' : o.v)} className={`px-3 py-1.5 rounded-lg border text-xs font-semibold transition-all ${chip(value === o.v)}`}>{o.l}</button>)}</div>;

  const ActivityCard = ({ activity, why, duration, effort, category, showAdd, showRate, showNudge, menuTarget }) => {
    const ci = catInfo(category); const onMenu = myMenu.find(a => a.name === activity);
    return <div className={`${c.card} border ${c.border} rounded-lg p-4 space-y-2`}>
      <div className="flex items-start justify-between gap-2"><h4 className={`text-sm font-bold ${c.text} flex-1`}>{activity}</h4><div className="flex items-center gap-1.5 flex-shrink-0">{duration && <span className={`text-xs px-2 py-0.5 rounded-full ${c.cardAlt} ${c.textMuted}`}>{duration}</span>}{effort && <span className={`text-xs px-2 py-0.5 rounded-full border ${isDark ? `border-${ci.color}-700 text-${ci.color}-300` : `border-${ci.color}-300 text-${ci.color}-800`}`}>{ci.emoji} {effort}</span>}</div></div>
      {why && <p className={`text-xs ${c.textSecondary}`}>{why}</p>}
      <div className="flex items-center gap-2 pt-1">
        {showAdd && !onMenu && <button onClick={() => addToMenu(activity, category, effort, duration, null, null, null, menuTarget)} className={`text-xs font-bold px-2 py-1 rounded ${c.btnSecondary}`}>+ {menuTarget === 'partner' ? 'Partner' : 'My'} Menu</button>}
        {onMenu && <span className={`text-xs ${isDark ? 'text-emerald-400' : 'text-emerald-600'}`}>✓ On menu</span>}
        {showRate && <button onClick={() => { setRatingActivity({ activity, category }); setRateResult(null); setRateNote(''); setRateAnchor(''); }} className={`text-xs font-bold px-2 py-1 rounded ${c.btnSecondary}`}>⭐ Rate</button>}
        {showNudge && <button onClick={() => handleNudge(activity)} className={`text-xs font-bold px-2 py-1 rounded ${c.btnSecondary}`}>👥 Invite</button>}
      </div>
    </div>;
  };

  // v5: Energy Chart
  const EnergyChart = () => {
    const data = activityLog.slice(0, 6).reverse();
    if (!data.length) return null;
    const maxE = 10; const h = 100; const w = Math.max(data.length * 50, 200);
    return <div className={`${c.card} rounded-xl shadow-lg p-5`}>
      <div className="flex justify-between mb-3"><h4 className={`font-bold text-sm ${c.text}`}>📈 Energy Before/After</h4><button onClick={() => setShowEnergyChart(false)} className={`text-xs ${c.textMuted}`}>✕</button></div>
      <div className="overflow-x-auto"><svg width={w} height={h + 30} className="w-full" viewBox={`0 0 ${w} ${h + 30}`}>
        {data.map((d, i) => {
          const x = i * (w / data.length) + (w / data.length) / 2;
          const yB = h - (d.energy_before / maxE) * h; const yA = h - (d.energy_after / maxE) * h;
          const bColor = isDark ? 'rgb(248,113,113)' : 'rgb(239,68,68)'; const aColor = isDark ? 'rgb(52,211,153)' : '#10b981';
          return <g key={i}>
            <line x1={x} y1={yB} x2={x} y2={yA} stroke={d.energy_after >= d.energy_before ? aColor : bColor} strokeWidth="2" strokeDasharray="3,2" />
            <circle cx={x} cy={yB} r="4" fill={bColor} />
            <circle cx={x} cy={yA} r="4" fill={aColor} />
            <text x={x} y={h + 15} textAnchor="middle" className={`text-xs ${c.textMuted}`} fill="currentColor" style={{ fontSize: '9px' }}>{d.rating}/10</text>
          </g>;
        })}
      </svg></div>
      <div className="flex gap-4 mt-2"><span className={`text-xs flex items-center gap-1 ${c.textMuted}`}><span className="w-2 h-2 rounded-full" style={{ backgroundColor: isDark ? 'rgb(248,113,113)' : '#ef4444' }} /> Before</span><span className={`text-xs flex items-center gap-1 ${c.textMuted}`}><span className="w-2 h-2 rounded-full" style={{ backgroundColor: isDark ? 'rgb(52,211,153)' : '#10b981' }} /> After</span></div>
    </div>;
  };

  // ─── Menu section (reusable for personal + partner) ───
  const MenuSection = ({ menu, setter, target, title, emoji }) => (
    <div className="space-y-2">{Object.entries(CATEGORIES).map(([key, info]) => {
      const items = menu.filter(a => a.category === key); if (!items.length) return null;
      return <div key={key}><p className={`text-xs font-bold ${c.textMuted} mb-1`}>{info.emoji} {info.label}</p>{items.map(a => <div key={a.id} className={`flex items-center justify-between gap-2 ${c.cardAlt} rounded-lg p-2 mb-1`}><div className="flex-1 min-w-0"><span className={`text-sm ${c.text} block truncate`}>{a.name}</span><div className="flex gap-2 text-xs">{a.avg_rating && <span className={c.textMuted}>⭐ {a.avg_rating}/10 ({a.use_count}x)</span>}{a.sensory_anchor && <span className={isDark ? 'text-cyan-300' : 'text-cyan-600'}>🎵 {a.sensory_anchor}</span>}</div></div><button onClick={() => removeFromMenu(a.id, target)} className={`text-xs ${c.textMuted}`}>🗑️</button></div>)}</div>;
    })}</div>
  );

  // ═══ RENDER ═══
  return (
    <div className={`space-y-4 ${c.text}`}>
      <div className="max-w-4xl mx-auto space-y-4">
      <div className={`${c.card} border ${c.border} rounded-xl shadow-sm p-5`}>
        <div className="pb-3 border-b border-zinc-500">
          <div className="flex items-start justify-between gap-3">
            <div>
              <h2 className={`text-xl font-bold ${c.text} flex items-center gap-2`}>
                <span className="mr-2">{tool?.icon ?? '✨'}</span>{tool?.title ?? 'PEP'}
              </h2>
              <p className={`text-sm ${c.textSecondary}`}>{tool?.tagline ?? 'Personal Energy Planner — understand your energy, plan around it'}</p>
            </div>
            {(results || seqResult || timeAvail.trim() || recentActs.trim()) && (
              <button onClick={reset} className={`${c.btnSecondary} px-3 py-1.5 rounded-lg text-xs font-bold flex-shrink-0`}>
                ↺ Start Over
              </button>
            )}
          </div>
        </div>
      </div>

      {/* ═══ MODE TABS ═══ */}
      <p className={`text-xs ${c.textMuted} px-1`}>
        Mid-spiral and can't get to a plan? <a href="/SpiralStopper" className={linkStyle}>🌀 Spiral Stopper</a> first.
      </p>
      <div className={`flex gap-1 p-1 rounded-xl ${c.cardAlt}`}>
        {MODES.map(m => <button key={m.id} onClick={() => setMode(m.id)} className={`flex-1 py-2.5 px-2 rounded-lg text-xs font-bold transition-all text-center ${mode === m.id ? (isDark ? 'bg-zinc-700 text-emerald-300 shadow' : 'bg-white text-emerald-700 shadow') : `${c.textMuted} hover:${isDark ? 'text-zinc-200' : 'text-gray-700'}`}`}><span className="block text-base mb-0.5">{m.icon}</span>{m.label}</button>)}
      </div>

      {/* ═══ RECHARGE MODE ═══ */}
      {mode === 'recharge' && <>
      {/* Nav */}
      <div className="flex flex-wrap gap-2">
        <button onClick={() => { setShowMyMenu(!showMyMenu); setShowPartnerMenu(false); setBuildMenuResult(null); }} className={`text-xs font-bold ${isDark ? 'text-emerald-300' : 'text-emerald-600'}`}>📋 My Menu ({myMenu.length})</button>
        <button onClick={() => { setShowPartnerMenu(!showPartnerMenu); setShowMyMenu(false); setBuildMenuResult(null); }} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>👯 Partner ({partnerMenu.length})</button>
        {myMenu.length > 0 && <button onClick={handleEnergyMatch} disabled={matchLoading} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'} disabled:opacity-40`}>{matchLoading ? (tool?.icon ?? '✨') : '🎯 Match'}</button>}
        {myMenu.length >= 3 && <button onClick={handleSurprise} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>🎰 Surprise Me</button>}
        {activityLog.length >= 3 && <button onClick={handlePatterns} disabled={patternLoading} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'} disabled:opacity-40`}>{patternLoading ? (tool?.icon ?? '✨') : '🔍 Patterns'}</button>}
        {activityLog.length >= 5 && <button onClick={handleInsights} disabled={insightsLoading} className={`text-xs font-bold ${isDark ? 'text-amber-300' : 'text-amber-600'} disabled:opacity-40`}>{insightsLoading ? (tool?.icon ?? '✨') : '📊 Insights'}</button>}
        {activityLog.length >= 2 && <button onClick={() => setShowEnergyChart(!showEnergyChart)} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>📈 Chart</button>}
        {activityLog.length >= 3 && <button onClick={handleDebtCheck} disabled={debtLoading} className={`text-xs font-bold ${isDark ? 'text-red-300' : 'text-red-600'} disabled:opacity-40`}>{debtLoading ? (tool?.icon ?? '✨') : '🌡️ Debt check'}</button>}
        {savedSequences.length > 0 && <button onClick={() => setShowSavedSeqs(!showSavedSeqs)} className={`text-xs font-bold ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>🌙 Routines ({savedSequences.length})</button>}
      </div>

      {/* Checkin timer + fired */}
      {checkinTimer && <div className={`${c.timer} border rounded-xl p-4 flex items-center justify-between`}><div><p className={`text-sm font-bold ${c.text}`}>🔔 Check-in scheduled</p>{checkinResult?.prep_tip && <p className={`text-xs ${c.textSecondary}`}>💡 {checkinResult.prep_tip}</p>}</div><div className="text-right"><span className={`text-lg font-bold ${c.text}`}>{formatMs(checkinRemaining)}</span><button onClick={() => { setCheckinTimer(null); clearInterval(timerRef.current); }} className={`block text-xs ${c.textMuted} mt-1`}>Cancel</button></div></div>}
      {checkinRemaining === 0 && checkinResult && <div className={`${c.success} border-2 rounded-xl p-5 space-y-3`}><h4 className={`font-bold text-lg ${c.text}`}>⏰ Time to recharge!</h4><p className="text-sm">{checkinResult.reminder_message}</p>{checkinResult.suggested_activity && <ActivityCard activity={checkinResult.suggested_activity.activity} why={checkinResult.suggested_activity.why} duration={checkinResult.suggested_activity.duration} category="medium_recharge" showAdd showRate />}<button onClick={() => { setCheckinRemaining(null); setCheckinResult(null); }} className={`text-xs ${c.textMuted}`}>Dismiss</button></div>}

      {/* Surprise Me lock */}
      {surpriseActivity && <div className={`${c.subtle} border-2 rounded-xl p-5 space-y-3`}><div className="flex justify-between items-center"><h4 className={`font-bold text-sm ${c.text}`}>🎰 Your pick: commit for 10 minutes</h4>{surpriseLock && <span className={`text-lg font-bold ${c.text}`}>{formatMs(surpriseRemaining)}</span>}</div>
        <div className={`${c.card} border ${c.border} rounded-lg p-4`}><h4 className={`text-lg font-bold ${c.text}`}>{surpriseActivity.name}</h4><p className={`text-xs ${c.textSecondary}`}>{catInfo(surpriseActivity.category).emoji} {surpriseActivity.category} · {surpriseActivity.duration}{surpriseActivity.sensory_anchor && <span className={isDark ? ' text-cyan-300' : ' text-cyan-600'}> · 🎵 {surpriseActivity.sensory_anchor}</span>}</p></div>
        {surpriseLock && surpriseRemaining > 0 ? <p className={`text-xs ${c.textSecondary}`}>Try it for 10 minutes before re-rolling. You picked this for a reason.</p> : <div className="flex gap-2"><button onClick={() => { setRatingActivity({ activity: surpriseActivity.name, category: surpriseActivity.category }); setRateResult(null); }} className={`text-xs font-bold px-3 py-1.5 rounded ${c.btnPrimary}`}>⭐ Rate it</button><button onClick={handleSurprise} className={`text-xs font-bold px-3 py-1.5 rounded ${c.btnSecondary}`}>🎰 Re-roll</button><button onClick={() => { setSurpriseActivity(null); setSurpriseLock(null); }} className={`text-xs ${c.textMuted}`}>Close</button></div>}
      </div>}

      {/* Debt check result */}
      {debtResult && <div className={`${c[DEBT_COLORS[debtResult.debt_level] || 'warn']} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🌡️ Recharge Debt: {debtResult.debt_level}</h4><button onClick={() => setDebtResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div><p className="text-sm">{debtResult.debt_summary}</p>{debtResult.days_since_good_recharge && <p className={`text-xs ${c.textSecondary}`}>Last good recharge: {debtResult.days_since_good_recharge}</p>}<p className="text-xs font-bold">💊 {debtResult.prescription}</p>{debtResult.gentle_warning && <p className={`text-xs italic ${c.textSecondary}`}>⚠️ {debtResult.gentle_warning}</p>}<p className={`text-xs font-bold ${isDark ? 'text-emerald-400' : 'text-emerald-600'}`}>→ {debtResult.first_step}</p></div>}

      {/* Energy chart */}
      {showEnergyChart && <EnergyChart />}

      {/* Panels: insights, patterns, match — same as v4 */}
      {insightsResult && <div className={`${c.warning} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">📊 Dashboard</h4><button onClick={() => setInsightsResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div>{insightsResult.dashboard && <div className="grid grid-cols-3 gap-3">{[['🔋', 'Rating', insightsResult.dashboard.avg_rating], ['⬆️', 'Gain', insightsResult.dashboard.avg_energy_gain], ['✅', 'High%', insightsResult.dashboard.high_rated_pct], ['📊', '#', insightsResult.dashboard.total_sessions], ['🏆', 'Best', insightsResult.dashboard.best_category], ['📈', 'Trend', insightsResult.trend]].map(([e, l, v], i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-2 text-center`}><span className="text-xs">{e} {l}</span><br /><span className={`text-sm font-bold ${c.text}`}>{v}</span></div>)}</div>}<p className={`text-sm ${c.textSecondary}`}>{insightsResult.trend_detail}</p>{insightsResult.recommendation && <p className="text-xs font-bold">💡 {insightsResult.recommendation}</p>}</div>}
      {patternResult && <div className={`${c.subtle} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🔍 Patterns</h4><button onClick={() => setPatternResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div><p className={`text-sm ${c.textSecondary}`}>{patternResult.summary}</p>{patternResult.top_restorers?.length > 0 && <div><p className="text-xs font-bold mb-1">🏆 Top:</p>{patternResult.top_restorers.map((t, i) => <p key={i} className={`text-xs ${c.textSecondary}`}>• {t.activity} ({t.avg_rating}/10, {t.avg_energy_gain})</p>)}</div>}{patternResult.numbing_traps?.length > 0 && <div><p className="text-xs font-bold mb-1">⚠️ Traps:</p>{patternResult.numbing_traps.map((t, i) => <p key={i} className={`text-xs ${c.textSecondary}`}>• {t.activity} ({t.times_chosen}x, {t.avg_rating}/10) — {t.nudge}</p>)}</div>}{patternResult.mood_patterns?.length > 0 && <div><p className="text-xs font-bold mb-1">🌦️ Mood:</p>{patternResult.mood_patterns.map((m, i) => <p key={i} className={`text-xs ${c.textSecondary}`}>• {m.mood}: {m.best_activity}</p>)}</div>}<p className="text-xs font-bold">💡 {patternResult.best_insight}</p></div>}
      {matchResult && <div className={`${c.highlight} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🎯 From your menu</h4><button onClick={() => setMatchResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div>{(matchResult.matched || []).map((m, i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-3`}><span className={`text-sm font-bold ${c.text}`}>#{m.rank} {m.activity}</span><p className={`text-xs ${c.textSecondary}`}>{m.why_now}</p>{m.anchor_reminder && <p className={`text-xs ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>🎵 {m.anchor_reminder}</p>}<button onClick={() => { setRatingActivity({ activity: m.activity, category: '?' }); setRateResult(null); setRateAnchor(''); }} className={`text-xs font-bold ${c.textMuted} mt-1`}>⭐ Did it</button></div>)}{matchResult.gap_note && <p className={`text-xs ${c.textSecondary}`}>📋 {matchResult.gap_note}</p>}</div>}

      {/* Rating overlay */}
      {ratingActivity && <div className={`${c.card} border-2 ${isDark ? 'border-amber-600' : 'border-amber-400'} rounded-xl p-5 space-y-4`}>
        <div className="flex justify-between"><h4 className={`font-bold text-sm ${c.text}`}>⭐ Rate: {ratingActivity.activity}</h4><button onClick={() => { setRatingActivity(null); setRateResult(null); }} className={`text-xs ${c.textMuted}`}>✕</button></div>
        <div><label className={`text-xs font-bold ${c.textSecondary}`}>Restorative? {rateScore}/10</label><input type="range" min="1" max="10" value={rateScore} onChange={e => setRateScore(parseInt(e.target.value))} className="w-full h-2 rounded-lg cursor-pointer accent-amber-500" /></div>
        <div><label className={`text-xs font-bold ${c.textSecondary}`}>Energy after: {energyAfter}/10 {ENERGY_EMOJIS[energyAfter]}</label><input type="range" min="1" max="10" value={energyAfter} onChange={e => setEnergyAfter(parseInt(e.target.value))} className="w-full h-2 rounded-lg cursor-pointer accent-emerald-500" /></div>
        <input value={rateNote} onChange={e => setRateNote(e.target.value)} placeholder="Thoughts? (optional)" className={`w-full p-2 border rounded-lg text-sm ${c.input}`} />
        <input value={rateAnchor} onChange={e => setRateAnchor(e.target.value)} placeholder="🎵 Sensory anchor? (song, scent, image...)" className={`w-full p-2 border rounded-lg text-sm ${c.input}`} />
        <button onClick={handleRate} disabled={rateLoading} className={`w-full py-2.5 rounded-xl text-sm font-bold ${c.btnPrimary} disabled:opacity-40`}>{rateLoading ? (tool?.icon ?? '✨') : '⭐ Log & Reflect'}</button>
        {rateResult && <div className={`${c.success} border rounded-lg p-4 space-y-2`}><p className="text-sm">{rateResult.reflection}</p>{rateResult.anchor_suggestion && rateResult.anchor_suggestion !== 'null' && <p className={`text-xs ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>🎵 {rateResult.anchor_suggestion}</p>}{rateResult.pattern_hint && <p className="text-xs font-bold">🔍 {rateResult.pattern_hint}</p>}</div>}
      </div>}
      {nudgeResult && <div className={`${c.success} border rounded-xl p-4 space-y-2`}><div className="flex justify-between"><span className="text-xs font-bold">👥 Invite</span><button onClick={() => setNudgeResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div><p className="text-sm">{nudgeResult.message}</p></div>}

      {/* My Menu / Partner Menu */}
      {(showMyMenu || showPartnerMenu) && <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-4`}>
        <div className="flex justify-between items-center"><h3 className={`font-bold text-sm ${c.text}`}>{showPartnerMenu ? '👯 Partner Menu' : '📋 My Menu'}</h3><button onClick={() => { setShowMyMenu(false); setShowPartnerMenu(false); }} className={`text-xs ${c.textMuted}`}>✕</button></div>
        {(showPartnerMenu ? partnerMenu : myMenu).length === 0 ? <p className={`text-center text-sm ${c.textSecondary} py-4`}>{showPartnerMenu ? 'Add activities you do together' : 'Save activities from your menu or let AI suggest'}</p> : <MenuSection menu={showPartnerMenu ? partnerMenu : myMenu} setter={showPartnerMenu ? setPartnerMenu : setMyMenu} target={showPartnerMenu ? 'partner' : 'personal'} />}
        <div className={`${c.cardAlt} rounded-lg p-4 space-y-3 border ${c.border}`}>
          <p className={`text-xs font-bold ${c.text}`}>✨ AI {showPartnerMenu ? 'Partner' : 'Menu'} Builder</p>
          <input value={buildInterests} onChange={e => setBuildInterests(e.target.value)} placeholder={showPartnerMenu ? "Shared interests? (cooking, hiking, games...)" : "Your interests? (cooking, nature, puzzles...)"} className={`w-full p-2 border rounded-lg text-sm ${c.input}`} />
          <button onClick={() => handleBuildMenu(showPartnerMenu)} disabled={buildMenuLoading} className={`w-full py-2 rounded-xl text-sm font-bold ${c.btnPrimary} disabled:opacity-40`}>{buildMenuLoading ? (tool?.icon ?? '✨') : `✨ Suggest ${showPartnerMenu ? 'partner' : ''} activities`}</button>
          {buildMenuResult && <div className="space-y-2">{buildMenuResult.menu_balance_note && <p className={`text-xs ${c.textSecondary}`}>📊 {buildMenuResult.menu_balance_note}</p>}{(buildMenuResult.suggestions || []).map((s, i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-3 space-y-1`}><div className="flex items-start justify-between gap-2"><span className={`text-sm font-bold ${c.text}`}>{s.activity}</span><button onClick={() => addToMenu(s.activity, s.category, s.effort, s.duration, s.energy_min, s.energy_max, s.environments, showPartnerMenu ? 'partner' : 'personal')} className={`text-xs font-bold px-2 py-1 rounded flex-shrink-0 ${c.btnPrimary}`}>+ Add</button></div><p className={`text-xs ${c.textSecondary}`}>{s.why_add}</p></div>)}</div>}
        </div>
      </div>}

      {/* Saved Sequences */}
      {showSavedSeqs && <div className={`${c.timer} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🌙 Saved Routines</h4><button onClick={() => setShowSavedSeqs(false)} className={`text-xs ${c.textMuted}`}>✕</button></div>
        {savedSequences.map(seq => <div key={seq.id} className={`${c.card} border ${c.border} rounded-lg p-3`}><div className="flex items-center justify-between"><div><span className={`text-sm font-bold ${c.text}`}>{seq.sequence_name}</span><span className={`text-xs ${c.textMuted} ml-2`}>{seq.total_time} · {seq.arc}</span></div><div className="flex gap-2"><button onClick={() => { setSeqResult(seq); setSeqStep(0); setShowSavedSeqs(false); }} className={`text-xs font-bold px-2 py-1 rounded ${c.btnPrimary}`}>▶ Play</button><button onClick={() => setSavedSequences(p => p.filter(s => s.id !== seq.id))} className={`text-xs ${c.textMuted}`}>🗑️</button></div></div><div className="flex gap-1 mt-1">{(seq.steps || []).map((s, i) => <span key={i} className={`text-xs ${c.textMuted}`}>{i + 1}. {s.activity.slice(0, 6)}{s.activity.length > 25 ? '...' : ''}</span>)}</div></div>)}
      </div>}

      {/* ═══ JUST DO THIS overlay ═══ */}
      {justDoResult && <div className={`fixed inset-0 z-50 flex items-center justify-center p-6 ${isDark ? 'bg-zinc-900/95' : 'bg-white/95'}`}>
        <div className="max-w-md w-full text-center space-y-6">
          <p className={`text-4xl`}>🧊</p>
          <h3 className={`text-xl font-bold ${c.text}`}>Just do this.</h3>
          <div className={`${c.card} border-2 ${isDark ? 'border-emerald-600' : 'border-emerald-400'} rounded-xl p-6 text-left space-y-4`}>
            <p className={`text-lg font-bold ${c.text}`}>{justDoResult.activity}</p>
            <div className={`${c.success} border rounded-lg p-3`}><p className={`text-sm font-bold ${c.text}`}>→ {justDoResult.first_move}</p></div>
            <p className={`text-xs ${c.textSecondary}`}>{justDoResult.why_this}</p>
            <div className="flex justify-between text-xs"><span className={c.textMuted}>⏱️ {justDoResult.duration}</span><span className={c.textMuted}>✓ {justDoResult.done_signal}</span></div>
          </div>
          <p className={`text-xs ${c.textSecondary}`}>{justDoResult.after}</p>
          <div className="flex gap-3 justify-center">
            <button onClick={() => { addToMenu(justDoResult.activity, justDoResult.category, 'low', justDoResult.duration); setRatingActivity({ activity: justDoResult.activity, category: justDoResult.category }); setRateResult(null); setJustDoResult(null); }} className={`text-xs font-bold px-4 py-2 rounded-lg ${c.btnPrimary}`}>⭐ I did it</button>
            <button onClick={() => { setJustDoResult(null); handleJustDo(); }} className={`text-xs font-bold px-4 py-2 rounded-lg ${c.btnSecondary}`}>🔄 Different</button>
            <button onClick={() => setJustDoResult(null)} className={`text-xs font-bold px-4 py-2 rounded-lg ${c.btnSecondary}`}>← Back</button>
          </div>
        </div>
      </div>}

      {/* ═══ INPUT VIEW ═══ */}
      {!results && !seqResult && <div className="space-y-5">
        {/* Can't Even Choose */}
        <div className={`${c.cardAlt} border ${c.border} rounded-xl p-4`}>
          <p className={`text-sm font-semibold ${c.text} mb-1`}>Tell PEP how you feel — get a menu of what to do next</p>
          <p className={`text-xs ${c.textMuted}`}>Based on your energy and time, PEP suggests restorative activities matched to your current capacity — from quick 5-minute resets to deeper recovery. The lower your energy, the lighter the suggestions.</p>
        </div>

        <button onClick={handleJustDo} disabled={justDoLoading || loading} className={`w-full py-5 rounded-xl font-bold text-lg shadow-lg border-2 border-dashed transition-all ${justDoLoading ? (isDark ? 'border-zinc-600 text-zinc-500' : 'border-gray-300 text-gray-400') : (isDark ? 'border-emerald-600 text-emerald-300 hover:bg-emerald-900/20' : 'border-emerald-400 text-emerald-700 hover:bg-emerald-50')} disabled:opacity-40`}>{justDoLoading ? <span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> : '🧊'} I can't even choose — just tell me what to do</button>

        <div className={`${c.card} rounded-xl shadow-lg p-5`}><label className={`block font-semibold text-sm ${c.text} mb-1`}>How are you right now?</label><p className={`text-xs ${c.textMuted} mb-3`}>Pick the closest match — PEP will suggest activities that fit where you actually are.</p><div className="grid grid-cols-2 sm:grid-cols-4 gap-2">{QUICK_STATES.map((s, i) => <button key={i} onClick={() => handleQuickState(s)} disabled={loading} className={`px-3 py-3 rounded-lg border text-sm font-semibold text-center ${chip(false)} disabled:opacity-40`}>{s.label}</button>)}</div></div>

        <div className={`${c.card} rounded-xl shadow-lg p-5`}><div className="flex items-center justify-between mb-1"><label className={`font-semibold text-sm ${c.text}`}>Your energy right now</label><span className={`text-xs px-2 py-0.5 rounded-full ${c.cardAlt} ${c.textMuted}`}>{getTimeOfDayLabel(getTimeOfDay())}</span></div><div className="flex items-center gap-3 mb-2"><span className="text-3xl">{ENERGY_EMOJIS[energy]}</span><span className={`text-2xl font-bold ${c.text}`}>{energy}/10</span><span className={`text-sm ${c.textSecondary}`}>{ENERGY_LABELS[energy]}</span></div><input type="range" min="1" max="10" value={energy} onChange={e => setEnergy(parseInt(e.target.value))} className="w-full h-2.5 rounded-lg cursor-pointer accent-emerald-500" /><div className={`flex justify-between text-xs ${c.textMuted} mt-1`}><span>1 — Crashed</span><span>5 — Okay</span><span>10 — Fired up</span></div></div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className={`${c.card} rounded-xl shadow-lg p-5`}><label className={`block font-semibold text-sm ${c.text} mb-3`}>Current mood</label><Pill options={MOOD_OPTS} value={mood} setter={setMood} /></div>
          <div className={`${c.card} rounded-xl shadow-lg p-5`}><label className={`block font-semibold text-sm ${c.text} mb-3`}>Where are you?</label><Pill options={ENV_OPTS} value={environment} setter={setEnvironment} /></div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className={`${c.card} rounded-xl shadow-lg p-5`}><label className={`block font-semibold text-sm ${c.text} mb-3`}>Time available</label><Pill options={TIME_OPTS} value={timeAvail} setter={setTimeAvail} /></div>
          <div className={`${c.card} rounded-xl shadow-lg p-5`}><label className={`block font-semibold text-sm ${c.text} mb-1`}>What have you been doing?</label><p className={`text-xs ${c.textMuted} mb-2`}>Helps avoid more of the same.</p><input value={recentActs} onChange={e => setRecentActs(e.target.value)} placeholder="e.g. 'screens since 8am, back-to-back meetings'" className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} /></div>
        </div>

        <div className="flex gap-3">
          <button onClick={handleGenerate} disabled={loading} className={`flex-1 py-4 rounded-xl font-semibold text-lg flex items-center justify-center gap-2 shadow-lg ${loading ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : c.btnPrimary} disabled:opacity-40`}>{loading ? <><span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> Building...</> : <><span className="mr-1">{tool?.icon ?? '✨'}</span>Build Menu</>}</button>
          <button onClick={handleSequence} disabled={seqLoading} className={`px-6 py-4 rounded-xl font-semibold text-sm shadow-lg ${seqLoading ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : (isDark ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-emerald-600 hover:bg-emerald-700 text-white')} disabled:opacity-40`}>{seqLoading ? (tool?.icon ?? '✨') : '🎯 Sequence'}</button>
        </div>
      </div>}

      {/* ═══ SEQUENCE VIEW ═══ */}
      {seqResult && !results && <div className="space-y-5">
        <div className={`${c.card} rounded-xl shadow-lg p-5`}><div className="flex items-center justify-between mb-3"><h3 className={`text-lg font-bold ${c.text}`}>🎯 {seqResult.sequence_name}</h3><div className="flex gap-2"><button onClick={saveSequence} className={`text-xs font-bold px-3 py-1.5 rounded ${c.btnSecondary}`}>💾 Save</button><button onClick={() => { setSeqResult(null); setSeqStep(0); }} className={`text-xs font-bold ${isDark ? 'bg-red-900/30 text-red-300' : 'bg-red-50 text-red-700'} px-3 py-1.5 rounded-lg`}>✕</button></div></div><p className={`text-sm ${c.textSecondary}`}>{seqResult.arc_description}</p><p className={`text-xs ${c.textMuted}`}>{seqResult.total_time} · {seqResult.arc} arc</p></div>
        {(seqResult.steps || []).map((step, si) => { const isA = si === seqStep; const isD = si < seqStep; return <div key={si} className={`rounded-xl border-2 p-5 transition-all ${isD ? `opacity-50 ${c.card} ${c.border}` : isA ? `${c.card} ${isDark ? 'border-emerald-500' : 'border-emerald-400'} shadow-lg` : `${c.card} ${c.border}`}`}><div className="flex items-start gap-3"><div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 text-sm font-bold ${isD ? (isDark ? 'bg-emerald-900/40 text-emerald-400' : 'bg-emerald-100 text-emerald-700') : isA ? (isDark ? 'bg-emerald-900/40 text-emerald-300' : 'bg-emerald-100 text-emerald-700') : `${c.cardAlt} ${c.textMuted}`}`}>{isD ? '✓' : step.step}</div><div className="flex-1"><h4 className={`text-sm font-bold ${isD ? 'line-through' : ''} ${c.text}`}>{step.activity}</h4><p className={`text-xs ${c.textSecondary}`}>~{step.duration} · {step.effort}</p>{step.transition_from_previous && isA && <p className={`text-xs italic ${isDark ? 'text-cyan-300' : 'text-cyan-600'} mt-1`}>→ {step.transition_from_previous}</p>}</div>{isA && !isD && <button onClick={() => setSeqStep(si + 1)} className={`px-3 py-1.5 rounded-lg text-xs font-bold ${c.btnPrimary}`}>Done ✓</button>}</div></div>; })}
        {seqStep >= (seqResult.steps || []).length && <div className={`${c.success} border rounded-xl p-5 text-center`}><p className="text-lg mb-1">🎉</p><p className="text-sm font-bold">{seqResult.completion_feeling}</p></div>}
        <button onClick={() => { setSeqResult(null); setSeqStep(0); }} className={`text-xs ${c.textMuted}`}>← Back</button>
      </div>}

      {/* ═══ RESULTS ═══ */}
      {results && <div ref={resultsRef} className="space-y-5">
        <div className={`${c.card} rounded-xl shadow-lg p-4 flex items-center justify-between flex-wrap gap-3`}>
          <div className="flex items-center gap-2 flex-wrap"><span className={`text-sm font-semibold ${c.text}`}>{ENERGY_EMOJIS[energy]} {energy}/10</span>{mood && <span className={`text-xs px-2 py-0.5 rounded-full ${c.warning} border`}>{MOOD_OPTS.find(m => m.v === mood)?.l}</span>}{environment && <span className={`text-xs px-2 py-0.5 rounded-full ${c.highlight} border`}>{ENV_OPTS.find(e => e.v === environment)?.l}</span>}<span className={`text-xs ${c.textMuted}`}>{getTimeOfDayLabel(getTimeOfDay())}</span></div>
          <div className="flex items-center gap-2 flex-wrap">
            <button onClick={() => setShowCheckin(!showCheckin)} className={`px-3 py-1.5 rounded-lg text-xs font-bold ${c.btnSecondary}`}>🔔 Remind me</button>
            <button onClick={handleSequence} disabled={seqLoading} className={`px-3 py-1.5 rounded-lg text-xs font-bold ${c.btnSecondary} disabled:opacity-40`}>{seqLoading ? (tool?.icon ?? '✨') : '🎯 Build a plan'}</button>
          </div>
        </div>

        {showCheckin && <div className={`${c.timer} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🔔 Schedule Check-in</h4><button onClick={() => setShowCheckin(false)} className={`text-xs ${c.textMuted}`}>✕</button></div><div className="flex gap-2">{CHECKIN_OPTS.map(o => <button key={o.v} onClick={() => setCheckinMinutes(o.v)} className={`px-3 py-1.5 rounded-lg border text-xs font-semibold ${chip(checkinMinutes === o.v)}`}>{o.l}</button>)}</div><button onClick={handleCheckin} disabled={checkinLoading} className={`w-full py-2.5 rounded-xl text-sm font-bold ${c.btnPrimary} disabled:opacity-40`}>{checkinLoading ? (tool?.icon ?? '✨') : `🔔 Set ${checkinMinutes}m`}</button></div>}

        {results.mood_note && results.mood_note !== 'null' && <div className={`${c.warning} border rounded-xl p-4`}><p className="text-sm">🌦️ {results.mood_note}</p></div>}
        {results.time_note && results.time_note !== 'null' && <div className={`${c.highlight} border rounded-xl p-4`}><p className="text-sm">🕐 {results.time_note}</p></div>}
        {results.energy_read && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">{results.energy_read}</p></div>}

        {results.menu?.top_pick && <div className={`${c.card} rounded-xl shadow-lg border-2 ${isDark ? 'border-emerald-600' : 'border-emerald-400'} p-5`}><div className="flex items-center gap-2 mb-2"><span className="text-xl">⭐</span><h3 className={`text-lg font-bold ${c.text}`}>Top Pick</h3></div><ActivityCard activity={results.menu.top_pick.activity} why={results.menu.top_pick.why} duration={results.menu.top_pick.duration} effort={results.menu.top_pick.effort} category={results.menu.top_pick.category} showAdd showRate showNudge />{results.transition_tip && <p className={`text-xs ${c.textSecondary} mt-3`}>→ <b>First step:</b> {results.transition_tip}</p>}</div>}

        {results.menu?.quick_hits?.length > 0 && <div className={`${c.card} rounded-xl shadow-lg p-5`}><h3 className={`font-bold text-sm ${c.text} mb-3`}>⚡ Quick Hits</h3><div className="space-y-2">{results.menu.quick_hits.map((a, i) => <ActivityCard key={i} activity={a.activity} why={a.why} duration={a.duration} effort={a.effort} category="quick_hit" showAdd showRate />)}</div></div>}
        {results.menu?.medium_recharges?.length > 0 && <div className={`${c.card} rounded-xl shadow-lg p-5`}><h3 className={`font-bold text-sm ${c.text} mb-3`}>🔋 Medium Recharges</h3><div className="space-y-2">{results.menu.medium_recharges.map((a, i) => <ActivityCard key={i} activity={a.activity} why={a.why} duration={a.duration} effort={a.effort} category="medium_recharge" showAdd showRate showNudge />)}</div></div>}
        {results.menu?.deep_resets?.length > 0 && <div className={`${c.card} rounded-xl shadow-lg p-5`}><h3 className={`font-bold text-sm ${c.text} mb-3`}>🌊 Deep Resets</h3><div className="space-y-2">{results.menu.deep_resets.map((a, i) => <ActivityCard key={i} activity={a.activity} why={a.why} duration={a.duration} effort={a.effort} category="deep_reset" showAdd showRate showNudge />)}</div></div>}
        {results.menu?.avoid_right_now?.length > 0 && <div className={`${c.danger} border rounded-xl p-5`}><h3 className="font-bold text-sm mb-3">⚠️ Skip</h3>{results.menu.avoid_right_now.map((a, i) => <div key={i} className="mb-2"><p className={`text-sm font-bold ${c.text}`}>{a.activity}</p><p className={`text-xs ${c.textSecondary}`}>{a.why}</p></div>)}</div>}
        {results.pleasure_vs_numbing && <div className={`${c.highlight} border rounded-xl p-4`}><p className="text-sm">💡 {results.pleasure_vs_numbing}</p></div>}

        {!swapResult && <button onClick={() => handleSwap((results.menu?.quick_hits || []).concat(results.menu?.medium_recharges || []).map(a => a.activity).slice(0, 6))} disabled={swapLoading} className={`w-full py-3 rounded-xl text-sm font-bold border-2 border-dashed ${isDark ? 'border-zinc-600 text-zinc-400' : 'border-gray-300 text-gray-500'} disabled:opacity-40`}>{swapLoading ? (tool?.icon ?? '✨') : '🔄 Not feeling these — show me different ones'}</button>}
        {swapResult && <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-3`}>
          <div>
            <h3 className={`font-bold text-sm ${c.text}`}>🔄 Fresh suggestions</h3>
            <p className={`text-xs ${c.textMuted}`}>Different activities based on what you skipped</p>
          </div>
          {swapResult.read && <p className={`text-xs ${c.textSecondary}`}>{swapResult.read}</p>}
          <div className="space-y-2">{(swapResult.alternatives || []).map((a, i) => <ActivityCard key={i} activity={a.activity} why={a.why_different} duration={a.duration} effort={a.effort} category={a.category} showAdd showRate />)}</div>
          {swapResult.wildcard && <div className={`${c.subtle} border rounded-lg p-3`}><p className={`text-xs font-bold ${c.text}`}>🎲 {swapResult.wildcard.activity}</p><p className={`text-xs ${c.textSecondary}`}>{swapResult.wildcard.why}</p></div>}
        </div>}

        {seqResult && <div className={`${c.timer} border rounded-xl p-5 space-y-3`}><div className="flex justify-between"><h4 className="font-bold text-sm">🎯 {seqResult.sequence_name}</h4><div className="flex gap-2"><button onClick={saveSequence} className={`text-xs font-bold ${c.textMuted}`}>💾</button><button onClick={() => setSeqResult(null)} className={`text-xs ${c.textMuted}`}>✕</button></div></div>{(seqResult.steps || []).map((step, si) => <div key={si} className={`flex items-center gap-2 ${si < seqStep ? 'opacity-50' : ''}`}><span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${si < seqStep ? c.success : si === seqStep ? (isDark ? 'bg-emerald-900/40 text-emerald-300' : 'bg-emerald-100 text-emerald-700') : `${c.cardAlt} ${c.textMuted}`}`}>{si < seqStep ? '✓' : step.step}</span><span className={`text-xs flex-1 ${si < seqStep ? 'line-through' : ''} ${c.textSecondary}`}>{step.activity}</span>{si === seqStep && <button onClick={() => setSeqStep(si + 1)} className={`text-xs font-bold px-2 py-1 rounded ${c.btnPrimary}`}>✓</button>}</div>)}{seqStep >= (seqResult.steps || []).length && <p className={`text-sm font-bold ${isDark ? 'text-emerald-400' : 'text-emerald-600'}`}>🎉 {seqResult.completion_feeling}</p>}</div>}


        {/* Cross-references */}
        <p className={`text-xs ${c.textMuted} text-center`}>
          AI-generated suggestions — you know your energy best.{' '}
          Feeling a crash coming?{' '}<a href="/CrashPredictor" className={linkStyle}>Crash Predictor</a>{' '}
          maps the pattern.{' '}<a href="/BrainStateDeejay" className={linkStyle}>Brain State Deejay</a>{' '}
          matches your current state to the right kind of focus.
        </p>
      </div>}
      </>}

      {/* ═══ BUDGET MODE ═══ */}
      {mode === 'budget' && <>
        <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-4`}>
          <div>
              <h3 className={`font-bold text-lg ${c.text}`}>🥄 Energy Budget</h3>
              <p className={`text-xs ${c.textSecondary}`}>Map your tasks against your available energy — see what actually fits</p>
              <p className={`text-xs ${c.textMuted} mt-1`}>Set your energy level, list your tasks, and rate how draining each one is. The tool figures out what fits today and what to defer.</p>
            </div>

          {/* Energy slider */}
          <div><div className="flex items-center gap-3 mb-2"><span className="text-2xl">{ENERGY_EMOJIS[energy]}</span><span className={`text-lg font-bold ${c.text}`}>{energy}/10</span><span className={`text-sm ${c.textSecondary}`}>{ENERGY_LABELS[energy]}</span></div><input type="range" min="1" max="10" value={energy} onChange={e => setEnergy(parseInt(e.target.value))} className="w-full h-2.5 rounded-lg cursor-pointer accent-emerald-500" /></div>

          {/* Task list */}
          <div className="space-y-3">
            {budgetTasks.map((t, i) => (
              <div key={i} className={`${c.cardAlt} border ${c.border} rounded-lg p-3 space-y-2`}>
                <div className="flex gap-2">
                  <input ref={el => { budgetTasksInputRefs.current[i] = el; }} value={t.task} onChange={e => updateBudgetTask(i, 'task', e.target.value)} placeholder={`Task ${i + 1}...`} className={`flex-1 p-2 border rounded-lg text-sm ${c.input}`} />
                  {budgetTasks.length > 1 && <button onClick={() => removeBudgetTask(i)} className={`text-xs ${c.textMuted}`}>🗑️</button>}
                </div>
                <div className="flex items-center gap-3">
                  <div className="flex-1"><label className={`text-xs ${c.textMuted}`}>Energy cost: {t.cost}/10 <span className="font-normal opacity-70">(1=easy, 10=draining)</span></label><input type="range" min="1" max="10" value={t.cost} onChange={e => updateBudgetTask(i, 'cost', parseInt(e.target.value))} className="w-full h-1.5 rounded-lg cursor-pointer accent-amber-500" /></div>
                  <div className="flex gap-1">{PRIORITY_OPTS.map(p => <button key={p.v} onClick={() => updateBudgetTask(i, 'priority', p.v)} className={`px-2 py-1 rounded text-xs font-semibold border ${chip(t.priority === p.v)}`}>{p.l}</button>)}</div>
                </div>
              </div>
            ))}
          </div>
          <button onClick={addBudgetTask} className={`w-full py-2 rounded-lg border-2 border-dashed text-sm font-semibold ${isDark ? 'border-zinc-600 text-zinc-400' : 'border-gray-300 text-gray-500'}`}>➕ Add task</button>
          <button onClick={handleBudget} disabled={loading} className={`w-full py-4 rounded-xl font-semibold text-lg ${loading ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : c.btnPrimary} disabled:opacity-40`}>{loading ? <><span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> Budgeting...</> : <><span className="mr-1">{tool?.icon ?? '✨'}</span>Budget my energy</>}</button>
        </div>

        {budgetResult && <div className="space-y-4">
          {/* Capacity bar */}
          <div className={`${c[budgetResult.capacity_status === 'within_budget' ? 'ok' : budgetResult.capacity_status === 'at_capacity' ? 'warn' : 'bad']} border-2 rounded-xl p-5`}>
            <div className="flex items-center justify-between mb-2"><h4 className={`font-bold text-lg ${c.text}`}>{budgetResult.capacity_status === 'within_budget' ? '✅' : budgetResult.capacity_status === 'at_capacity' ? '⚠️' : '🚨'} {(budgetResult.capacity_status || '').replace(/_/g, ' ').toUpperCase()}</h4><span className={`text-sm font-bold ${c.text}`}>{budgetResult.total_cost || 0}/{budgetResult.available || energy} energy</span></div>
            <div className={`w-full h-3 rounded-full ${isDark ? 'bg-zinc-700' : 'bg-gray-200'} overflow-hidden`}><div className="h-full rounded-full transition-all" style={{ width: `${Math.min(100, ((budgetResult.total_cost || 0) / (budgetResult.available || energy)) * 100)}%`, backgroundColor: budgetResult.capacity_status === 'within_budget' ? '#10b981' : budgetResult.capacity_status === 'at_capacity' ? '#f59e0b' : '#ef4444' }} /></div>
            <p className={`text-sm mt-2 ${c.textSecondary}`}>{budgetResult.energy_read}</p>
          </div>

          {/* Task plan */}
          <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-3`}>
            <h4 className={`font-bold text-sm ${c.text}`}>📋 Your plan</h4>
            {(budgetResult.task_plan || []).sort((a, b) => (a.order || 0) - (b.order || 0)).map((t, i) => (
              <div key={i} className={`${c.cardAlt} border-l-4 rounded-r-lg p-3 ${t.verdict === 'do' ? (isDark ? 'border-emerald-500' : 'border-emerald-400') : t.verdict === 'defer' ? (isDark ? 'border-amber-500' : 'border-amber-400') : (isDark ? 'border-zinc-600' : 'border-gray-300')}`}>
                <div className="flex items-start justify-between gap-2">
                  <div><span className={`text-sm font-bold ${t.verdict === 'drop' ? c.textMuted + ' line-through' : c.text}`}>{t.task}</span><p className={`text-xs ${c.textSecondary} mt-0.5`}>{t.reason}</p></div>
                  <div className="flex items-center gap-2 flex-shrink-0"><span className={`text-xs font-bold px-2 py-0.5 rounded-full ${t.verdict === 'do' ? c.success : t.verdict === 'defer' ? c.warning : c.danger} border`}>{t.verdict}</span><span className={`text-xs ${c.textMuted}`}>{t.cost} ⚡</span></div>
                </div>
              </div>
            ))}
          </div>

          {/* Permissions */}
          {budgetResult.permissions?.length > 0 && <div className={`${c.highlight} border rounded-xl p-5 space-y-2`}><h4 className="font-bold text-sm">💚 Permissions</h4>{budgetResult.permissions.map((p, i) => <p key={i} className="text-sm">{p}</p>)}</div>}
          {budgetResult.protection_suggestion && <div className={`${c.warning} border rounded-xl p-4`}><p className="text-sm font-bold">🛡️ Protect these: {budgetResult.protection_suggestion}</p></div>}
          {budgetResult.tomorrow_note && <div className={`${c.cardAlt} border ${c.border} rounded-xl p-4`}><p className={`text-sm ${c.textSecondary}`}>📅 Tomorrow: {budgetResult.tomorrow_note}</p></div>}

        </div>}
      </>}

      {/* ═══ FORECAST MODE ═══ */}
      {mode === 'forecast' && <>
        {!forecastResult ? <div className="space-y-4">
          <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-4`}>
            <div>
              <h3 className={`font-bold text-lg ${c.text}`}>🔋 Energy Forecast</h3>
              <p className={`text-xs ${c.textSecondary}`}>See how your week's events will drain your battery — before it happens</p>
              <p className={`text-xs ${c.textMuted} mt-1`}><span className="font-semibold">Energy type:</span> introverts drain in crowds and recharge alone; extroverts are the opposite. <span className="font-semibold">Battery:</span> how you feel right now, 0–100%.</p>
            </div>

            {/* Profile */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              <div><label className={`text-xs font-bold ${c.textSecondary}`}>Energy type</label><div className="flex items-center gap-2 mt-1"><span className="text-xs">🤫</span><input type="range" min="0" max="100" value={energyType} onChange={e => setEnergyType(parseInt(e.target.value))} className="flex-1 h-2 rounded-lg cursor-pointer accent-cyan-500" /><span className="text-xs">🎉</span></div><p className={`text-xs text-center ${c.textMuted}`}>{energyType < 30 ? 'Introvert' : energyType < 70 ? 'Ambivert' : 'Extrovert'}</p></div>
              <div><label className={`text-xs font-bold ${c.textSecondary}`}>Current battery: {currentBattery}% <span className="font-normal opacity-70">(how full are you right now?)</span></label><input type="range" min="10" max="100" step="5" value={currentBattery} onChange={e => setCurrentBattery(parseInt(e.target.value))} className="w-full h-2 rounded-lg cursor-pointer accent-emerald-500 mt-1" /></div>
              <div><label className={`text-xs font-bold ${c.textSecondary}`}>Recharge hours/day <span className="font-normal opacity-70">(alone time you need to feel okay)</span></label><div className="flex gap-1 mt-1">{[2, 3, 4, 6, 8].map(h => <button key={h} onClick={() => setRechargeHours(h)} className={`flex-1 py-1.5 rounded text-xs font-semibold border ${chip(rechargeHours === h)}`}>{h}h</button>)}</div></div>
            </div>
          </div>

          {/* Events */}
          <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-3`}>
            <h4 className={`font-bold text-sm ${c.text}`}>📅 Upcoming events</h4>
            {forecastEvents.map((ev, i) => (
              <div key={i} className={`${c.cardAlt} border ${c.border} rounded-lg p-3 space-y-2`}>
                <div className="flex gap-2">
                  <input ref={el => { forecastEventsInputRefs.current[i] = el; }} value={ev.name} onChange={e => updateForecastEvent(i, 'name', e.target.value)} placeholder="Event name..." className={`flex-1 p-2 border rounded-lg text-sm ${c.input}`} />
                  <button onClick={() => removeForecastEvent(i)} className={`text-xs ${c.textMuted}`}>🗑️</button>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                  <input value={ev.day} onChange={e => updateForecastEvent(i, 'day', e.target.value)} placeholder="Day (Mon, Tue...)" className={`p-1.5 border rounded text-xs ${c.input}`} />
                  <input value={ev.time} onChange={e => updateForecastEvent(i, 'time', e.target.value)} placeholder="Time (2pm...)" className={`p-1.5 border rounded text-xs ${c.input}`} />
                  <input value={ev.duration} onChange={e => updateForecastEvent(i, 'duration', e.target.value)} placeholder="Duration" className={`p-1.5 border rounded text-xs ${c.input}`} />
                  <input value={ev.people} onChange={e => updateForecastEvent(i, 'people', e.target.value)} placeholder="# people" className={`p-1.5 border rounded text-xs ${c.input}`} />
                </div>
                <div className="flex flex-wrap gap-1">
                  {EVENT_TYPES.map(t => <button key={t.v} onClick={() => updateForecastEvent(i, 'type', t.v)} className={`px-2 py-1 rounded text-xs border ${chip(ev.type === t.v)}`}>{t.l}</button>)}
                </div>
                <div className="flex gap-2 items-center">
                  <span className={`text-xs ${c.textMuted}`}>Role:</span>
                  {['attending', 'hosting', 'presenting'].map(r => <button key={r} onClick={() => updateForecastEvent(i, 'role', r)} className={`px-2 py-1 rounded text-xs border ${chip(ev.role === r)}`}>{r}</button>)}
                  <label className={`flex items-center gap-1 text-xs ${c.textSecondary} ml-auto`}><input type="checkbox" checked={ev.canLeave} onChange={e => updateForecastEvent(i, 'canLeave', e.target.checked)} /> Can leave early</label>
                </div>
              </div>
            ))}
            <button onClick={addForecastEvent} className={`w-full py-2 rounded-lg border-2 border-dashed text-sm font-semibold ${isDark ? 'border-zinc-600 text-zinc-400' : 'border-gray-300 text-gray-500'}`}>➕ Add event</button>
          </div>

          <button onClick={handleForecast} disabled={loading || !forecastEvents.length} className={`w-full py-4 rounded-xl font-semibold text-lg ${loading || !forecastEvents.length ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : c.btnPrimary} disabled:opacity-40`}>{loading ? <><span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> Forecasting...</> : <><span className="mr-1">{tool?.icon ?? '✨'}</span>Forecast my week</>}</button>
        </div>

        : <div className="space-y-4">
          {/* Weekly summary */}
          <div className={`${c[forecastResult.capacity_status === 'within_budget' ? 'ok' : forecastResult.capacity_status === 'tight' ? 'warn' : 'bad']} border-2 rounded-xl p-5`}>
            <div className="flex items-center justify-between mb-2"><h4 className={`font-bold text-lg ${c.text}`}>🔋 {forecastResult.capacity_status === 'within_budget' ? 'Looking good' : forecastResult.capacity_status === 'tight' ? 'Tight week' : 'Over-committed'}</h4><span className={`text-sm font-bold ${c.text}`}>{forecastResult.total_committed || 0}% / {forecastResult.weekly_capacity || 100}%</span></div>
            <div className={`w-full h-3 rounded-full ${isDark ? 'bg-zinc-700' : 'bg-gray-200'} overflow-hidden`}><div className="h-full rounded-full transition-all" style={{ width: `${Math.min(100, forecastResult.total_committed || 0)}%`, backgroundColor: (forecastResult.total_committed || 0) <= 70 ? '#10b981' : (forecastResult.total_committed || 0) <= 90 ? '#f59e0b' : '#ef4444' }} /></div>
            <p className={`text-sm mt-2 ${c.textSecondary}`}>{forecastResult.weekly_summary}</p>
          </div>

          {/* Event forecast */}
          <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-3`}>
            <h4 className={`font-bold text-sm ${c.text}`}>📊 Event-by-event drain</h4>
            {(forecastResult.forecast || []).map((f, i) => (
              <div key={i} className={`${c.cardAlt} border-l-4 rounded-r-lg p-3 ${f.battery_after < 20 ? (isDark ? 'border-red-500' : 'border-red-400') : f.battery_after < 40 ? (isDark ? 'border-amber-500' : 'border-amber-400') : (isDark ? 'border-emerald-500' : 'border-emerald-400')}`}>
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1"><span className={`text-sm font-bold ${c.text}`}>{f.event}</span><span className={`text-xs ${c.textMuted} ml-2`}>{f.day}</span><p className={`text-xs ${c.textSecondary} mt-0.5`}>{f.cost_breakdown}</p>{f.recovery_needed && <p className={`text-xs ${isDark ? 'text-cyan-300' : 'text-cyan-600'} mt-0.5`}>🔌 {f.recovery_needed}</p>}</div>
                  <div className="text-right flex-shrink-0">
                    <span className={`text-xs font-bold ${f.energy_cost > 30 ? (isDark ? 'text-red-400' : 'text-red-600') : c.textMuted}`}>-{f.energy_cost}%</span>
                    <div className={`text-lg font-bold ${f.battery_after < 20 ? (isDark ? 'text-red-400' : 'text-red-600') : f.battery_after < 40 ? (isDark ? 'text-amber-400' : 'text-amber-600') : (isDark ? 'text-emerald-400' : 'text-emerald-600')}`}>{f.battery_after}%</div>
                  </div>
                </div>
                {f.warning && <div className={`${c.danger} border rounded p-2 mt-2`}><p className="text-xs font-bold">⚠️ {f.warning}</p></div>}
                <button onClick={() => handleDecline(f.event)} className={`text-xs ${c.textMuted} mt-1`}>📝 Decline script</button>
              </div>
            ))}
          </div>

          {/* Decline message */}
          {declineResult && <div className={`${c.highlight} border rounded-xl p-5 space-y-2`}><div className="flex justify-between"><h4 className="font-bold text-sm">📝 Decline: {declineTarget}</h4><button onClick={() => { setDeclineResult(null); setDeclineTarget(null); }} className={`text-xs ${c.textMuted}`}>✕</button></div><p className={`text-sm ${c.textSecondary}`}>{declineResult.message}</p>{declineResult.alternative_offer && <p className={`text-xs ${isDark ? 'text-cyan-300' : 'text-cyan-600'}`}>💡 Alternative: {declineResult.alternative_offer}</p>}</div>}

          {/* Critical days + recovery plan */}
          {forecastResult.critical_days?.length > 0 && <div className={`${c.danger} border rounded-xl p-4`}><h4 className="font-bold text-sm mb-1">🚨 Critical days</h4>{forecastResult.critical_days.map((d, i) => <p key={i} className="text-sm">{d}</p>)}</div>}
          {forecastResult.recovery_plan && <div className={`${c.timer} border rounded-xl p-4`}><h4 className="font-bold text-sm mb-1">🔌 Recovery plan</h4><p className="text-sm">{forecastResult.recovery_plan}</p></div>}
          {forecastResult.permissions?.length > 0 && <div className={`${c.highlight} border rounded-xl p-5 space-y-2`}><h4 className="font-bold text-sm">💚 Permissions</h4>{forecastResult.permissions.map((p, i) => <p key={i} className="text-sm">{p}</p>)}</div>}
          {forecastResult.capacity_note && <div className={`${c.cardAlt} border ${c.border} rounded-xl p-4`}><p className={`text-sm ${c.textSecondary}`}>{forecastResult.capacity_note}</p></div>}

          <div className="flex gap-3">
            <button onClick={() => setForecastResult(null)} className={`px-4 py-2 rounded-lg text-sm font-bold ${c.btnSecondary}`}>← Edit events</button>
          </div>
        </div>}
      </>}

      {/* ═══ RADAR MODE ═══ */}
      {mode === 'radar' && <>
        <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-4`}>
          <div className="flex items-center justify-between">
            <div>
              <h3 className={`font-bold text-lg ${c.text}`}>📡 Burnout Radar</h3>
              <p className={`text-xs ${c.textSecondary}`}>15-second daily check-in — spots burnout patterns before you feel them</p>
              <p className={`text-xs ${c.textMuted} mt-1`}>Rate each dimension honestly. <span className="font-semibold">1 = struggling, 5 = solid</span>. Log daily for useful trends.</p>
            </div>
            {checkinLog.length > 0 && <span className={`text-xs px-2 py-1 rounded-full ${c.cardAlt} ${c.textMuted}`}>{checkinLog.length} day{checkinLog.length !== 1 ? 's' : ''} logged</span>}
          </div>

          {/* Quick-tap ratings */}
          {[
            { label: '😴 Sleep', val: radarSleep, set: setRadarSleep, low: 'barely slept', high: 'slept great' },
            { label: '🌤️ Mood', val: radarMood, set: setRadarMood, low: 'really low', high: 'feeling good' },
            { label: '⚡ Productivity', val: radarProd, set: setRadarProd, low: 'stuck/foggy', high: 'sharp & focused' },
            { label: '👥 Social energy', val: radarSocial, set: setRadarSocial, low: 'drained/avoidant', high: 'open & connected' },
          ].map(m => (
            <div key={m.label}>
              <div className="flex justify-between items-baseline">
                <label className={`text-sm font-semibold ${c.text}`}>{m.label}</label>
                <span className={`text-sm font-bold ${c.text}`}>{m.val}/5</span>
              </div>
              <div className="flex gap-1 mt-1">{[1, 2, 3, 4, 5].map(n => <button key={n} onClick={() => m.set(n)} className={`flex-1 py-2.5 rounded-lg text-sm font-bold border-2 transition-all ${n <= m.val ? (isDark ? 'bg-emerald-900/40 border-emerald-500 text-emerald-200' : 'bg-emerald-100 border-emerald-400 text-emerald-800') : `${c.cardAlt} ${c.border} ${c.textMuted}`}`}>{n}</button>)}</div>
              <div className={`flex justify-between text-[10px] ${c.textMuted} mt-0.5`}><span>1 = {m.low}</span><span>5 = {m.high}</span></div>
            </div>
          ))}

          <input value={radarSymptoms} onChange={e => setRadarSymptoms(e.target.value)} placeholder="Physical symptoms? (headaches, tension, fatigue...)" className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} />

          <button onClick={handleRadarCheckin} disabled={loading} className={`w-full py-4 rounded-xl font-semibold text-lg ${loading ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : c.btnPrimary} disabled:opacity-40`}>{loading ? <><span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> Checking in...</> : <>📡 Log today</>}</button>
        </div>

        {/* Checkin result */}
        {radarResult && <div className={`${c[RADAR_STATUS[radarResult.status]?.color || 'ok']} border-2 rounded-xl p-5 space-y-3`}>
          <div className="flex items-center gap-2"><span className="text-xl">{RADAR_STATUS[radarResult.status]?.icon || '🟢'}</span><h4 className={`font-bold text-lg ${c.text}`}>{radarResult.status_label || RADAR_STATUS[radarResult.status]?.label}</h4></div>
          <p className="text-sm">{radarResult.today_read}</p>
          {radarResult.trend_detail && <div className={`${c.cardAlt} rounded-lg p-3 border ${c.border}`}><p className={`text-xs font-bold ${c.text}`}>📈 Trend: {radarResult.trend}</p><p className={`text-xs ${c.textSecondary}`}>{radarResult.trend_detail}</p></div>}
          {radarResult.cross_signal_alert && <div className={`${c.danger} border rounded-lg p-3`}><p className="text-xs font-bold">🚨 {radarResult.cross_signal_alert}</p></div>}
          {radarResult.intervention && <div className={`${c.warning} border rounded-lg p-3`}><p className="text-xs font-bold">💊 Today: {radarResult.intervention}</p></div>}
          <p className={`text-xs ${c.textSecondary}`}>{radarResult.encouragement}</p>
        </div>}

        {/* History sparklines */}
        {checkinLog.length >= 3 && <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-3`}>
          <div className="flex items-center justify-between"><h4 className={`font-bold text-sm ${c.text}`}>📊 Trend</h4>{checkinLog.length >= 5 && <button onClick={handleRadarAnalyze} disabled={loading} className={`text-xs font-bold px-3 py-1.5 rounded-lg ${c.btnPrimary} disabled:opacity-40`}>{loading ? (tool?.icon ?? '✨') : '🔍 Full analysis'}</button>}</div>
          {['sleep', 'mood', 'productivity', 'social_energy'].map(metric => {
            const data = checkinLog.slice(0, 6).reverse();
            const label = { sleep: '😴', mood: '🌤️', productivity: '⚡', social_energy: '👥' }[metric];
            const vals = data.map(d => d[metric] || 3);
            const max = 5; const w = 200; const h = 40;
            return <div key={metric} className="flex items-center gap-3">
              <span className="text-sm w-6">{label}</span>
              <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} className="flex-1">
                <polyline fill="none" stroke={isDark ? 'rgb(52,211,153)' : '#10b981'} strokeWidth="2" points={vals.map((v, i) => `${(i / (vals.length - 1)) * w},${h - (v / max) * h}`).join(' ')} />
                {vals.map((v, i) => <circle key={i} cx={(i / (vals.length - 1)) * w} cy={h - (v / max) * h} r="3" fill={v <= 2 ? (isDark ? 'rgb(248,113,113)' : '#ef4444') : isDark ? 'rgb(52,211,153)' : '#10b981'} />)}
              </svg>
              <span className={`text-xs font-bold w-6 ${c.text}`}>{vals[vals.length - 1]}</span>
            </div>;
          })}
          <div className="flex gap-1">{checkinLog.slice(0, 6).reverse().map((d, i) => {
            const s = RADAR_STATUS[d.status] || RADAR_STATUS.green;
            return <div key={i} className={`flex-1 h-2 rounded-full ${d.status === 'green' ? (isDark ? 'bg-emerald-600' : 'bg-emerald-400') : d.status === 'yellow' ? (isDark ? 'bg-amber-600' : 'bg-amber-400') : d.status === 'orange' ? (isDark ? 'bg-amber-600' : 'bg-amber-400') : (isDark ? 'bg-red-600' : 'bg-red-400')}`} title={new Date(d.date).toLocaleDateString()} />;
          })}</div>
        </div>}

        {/* Full analysis */}
        {radarAnalysis && <div className="space-y-4">
          <div className={`${c[radarAnalysis.overall_risk === 'low' ? 'ok' : radarAnalysis.overall_risk === 'moderate' ? 'warn' : 'bad']} border-2 rounded-xl p-5`}>
            <h4 className={`font-bold text-lg ${c.text}`}>📡 Full Analysis</h4>
            <p className={`text-sm font-bold mt-1 ${c.text}`}>Risk: {(radarAnalysis.overall_risk || '').toUpperCase()}</p>
            <p className={`text-sm ${c.textSecondary} mt-1`}>{radarAnalysis.time_until_concern}</p>
            <p className={`text-sm mt-2`}>{radarAnalysis.reality_check}</p>
          </div>

          {radarAnalysis.metric_trends && <div className={`${c.card} rounded-xl shadow-lg p-5`}>
            <h4 className={`font-bold text-sm ${c.text} mb-3`}>📈 Metrics</h4>
            <div className="grid grid-cols-2 gap-3">{Object.entries(radarAnalysis.metric_trends).map(([k, v]) => <div key={k} className={`${c.cardAlt} border ${c.border} rounded-lg p-3`}><span className={`text-xs ${c.textMuted}`}>{k}</span><div className="flex items-center gap-2 mt-1"><span className={`text-lg font-bold ${v.direction === 'down' ? (isDark ? 'text-red-400' : 'text-red-600') : v.direction === 'up' ? (isDark ? 'text-emerald-400' : 'text-emerald-600') : c.text}`}>{v.avg}/5</span><span className={`text-xs ${c.textMuted}`}>{v.direction === 'down' ? '↘' : v.direction === 'up' ? '↗' : '→'} {v.change}</span></div></div>)}</div>
          </div>}

          {radarAnalysis.cross_signals?.length > 0 && <div className={`${c.warning} border rounded-xl p-4 space-y-1`}><h4 className="font-bold text-sm">🔗 Connected patterns</h4>{radarAnalysis.cross_signals.map((s, i) => <p key={i} className="text-sm">{s}</p>)}</div>}
          {radarAnalysis.biggest_concern && <div className={`${c.danger} border rounded-xl p-4`}><p className="text-sm font-bold">⚠️ Biggest concern: {radarAnalysis.biggest_concern}</p></div>}
          {radarAnalysis.interventions?.length > 0 && <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-2`}><h4 className={`font-bold text-sm ${c.text}`}>💊 Interventions</h4>{radarAnalysis.interventions.map((iv, i) => <div key={i} className={`${c[iv.priority === 'critical' ? 'bad' : iv.priority === 'high' ? 'warn' : 'info']} border rounded-lg p-3`}><div className="flex justify-between"><span className="text-sm font-bold">{iv.action}</span><span className={`text-xs px-2 py-0.5 rounded-full ${c.cardAlt}`}>{iv.priority}</span></div><p className={`text-xs ${c.textSecondary} mt-0.5`}>{iv.why}</p></div>)}</div>}
          {radarAnalysis.bright_spots && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">✨ {radarAnalysis.bright_spots}</p></div>}

        </div>}
      </>}

      {/* ═══ DISRUPTION MODE ═══ */}
      {mode === 'disruption' && <>
        {!disruptResult ? <div className="space-y-4">
          <div className={`${c.card} rounded-xl shadow-lg p-5 space-y-4`}>
            <div><h3 className={`font-bold text-lg ${c.text}`}>🔄 Routine Disruption</h3><p className={`text-xs ${c.textSecondary}`}>When life blows up your routine — get a temporary structure that fits</p></div>

            {/* Disruption type */}
            <div><label className={`text-xs font-bold ${c.textSecondary}`}>What happened?</label><div className="flex flex-wrap gap-2 mt-1">{DISRUPTION_TYPES.map(d => <button key={d.v} onClick={() => setDisruptType(d.v)} className={`px-3 py-2 rounded-lg border text-sm font-semibold ${chip(disruptType === d.v)}`}>{d.l}</button>)}</div></div>

            {/* Energy */}
            <div><div className="flex items-center gap-3 mb-1"><span className="text-xl">{ENERGY_EMOJIS[energy]}</span><span className={`text-sm font-bold ${c.text}`}>Energy: {energy}/10</span></div><input type="range" min="1" max="10" value={energy} onChange={e => setEnergy(parseInt(e.target.value))} className="w-full h-2 rounded-lg cursor-pointer accent-emerald-500" /></div>

            <textarea value={normalRoutine} onChange={e => setNormalRoutine(e.target.value)} onKeyDown={e => { if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) handleGenerate(); }} placeholder="What does your normal day look like? (brief)" rows={2} className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} />
            <input value={criticalTasks} onChange={e => setCriticalTasks(e.target.value)} placeholder="What MUST still happen? (meds, pet care, deadline...)" className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} />
            <input value={constraints} onChange={e => setConstraints(e.target.value)} placeholder="Constraints? (can't leave house, very low energy...)" className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} />
            <input value={disruptDuration} onChange={e => setDisruptDuration(e.target.value)} placeholder="How long will this last? (a day, a week, unknown...)" className={`w-full p-2.5 border rounded-lg text-sm ${c.input}`} />

            <button onClick={handleDisruption} disabled={loading || !disruptType} className={`w-full py-4 rounded-xl font-semibold text-lg ${loading || !disruptType ? (isDark ? 'bg-zinc-700 text-zinc-400' : 'bg-gray-200 text-gray-400') : c.btnPrimary} disabled:opacity-40`}>{loading ? <><span className="animate-spin inline-block">{tool?.icon ?? '✨'}</span> Building adapted routine...</> : <>🔄 Build my temporary routine</>}</button>
          </div>
        </div>

        : <div className="space-y-4">
          {/* Acknowledgment */}
          <div className={`${c.warning} border-2 rounded-xl p-5`}><p className={`text-lg ${c.text}`}>{disruptResult.acknowledgment}</p></div>

          {/* Keep */}
          {disruptResult.adapted_routine?.keep?.length > 0 && <div className={`${c.success} border rounded-xl p-5 space-y-2`}><h4 className="font-bold text-sm">✅ Keep doing</h4>{disruptResult.adapted_routine.keep.map((t, i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-3`}><span className={`text-sm font-bold ${c.text}`}>{t.task}</span><p className={`text-xs ${c.textSecondary}`}>{t.simplification}</p></div>)}</div>}

          {/* Simplify */}
          {disruptResult.adapted_routine?.simplify?.length > 0 && <div className={`${c.highlight} border rounded-xl p-5 space-y-2`}><h4 className="font-bold text-sm">🔽 Simplify</h4>{disruptResult.adapted_routine.simplify.map((t, i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-3`}><span className={`text-sm font-bold ${c.text}`}>{t.task}</span><p className={`text-xs ${c.textSecondary}`}>→ {t.simplified_version}</p></div>)}</div>}

          {/* Drop */}
          {disruptResult.adapted_routine?.drop?.length > 0 && <div className={`${c.cardAlt} border ${c.border} rounded-xl p-5 space-y-2`}><h4 className={`font-bold text-sm ${c.textMuted}`}>❌ Drop (for now)</h4>{disruptResult.adapted_routine.drop.map((t, i) => <div key={i} className={`${c.card} border ${c.border} rounded-lg p-3`}><span className={`text-sm ${c.textMuted} line-through`}>{t.task}</span><p className={`text-xs ${isDark ? 'text-emerald-300' : 'text-emerald-600'}`}>💚 {t.permission}</p></div>)}</div>}

          {/* Schedule + self-care */}
          {disruptResult.survival_schedule && <div className={`${c.card} rounded-xl shadow-lg p-5`}><h4 className={`font-bold text-sm ${c.text} mb-2`}>🕐 Temporary schedule</h4><p className={`text-sm ${c.textSecondary} whitespace-pre-line`}>{disruptResult.survival_schedule}</p></div>}
          {disruptResult.self_care_minimum && <div className={`${c.warning} border rounded-xl p-4`}><h4 className="font-bold text-sm mb-1">🛡️ Non-negotiable self-care</h4><p className="text-sm">{disruptResult.self_care_minimum}</p></div>}
          {disruptResult.return_trigger && <div className={`${c.timer} border rounded-xl p-4`}><h4 className="font-bold text-sm mb-1">🔄 When to resume normal</h4><p className="text-sm">{disruptResult.return_trigger}</p></div>}
          {disruptResult.duration_note && <p className={`text-sm ${c.textSecondary}`}>{disruptResult.duration_note}</p>}
          <div className={`${c.success} border-2 rounded-xl p-5`}><p className="text-sm font-bold">{disruptResult.reality_check}</p></div>

          <div className="flex gap-3">
            <button onClick={() => setDisruptResult(null)} className={`px-4 py-2 rounded-lg text-sm font-bold ${c.btnSecondary}`}>← Edit</button>
          </div>
        </div>}
      </>}
      </div>
    </div>
  );
};

PEP.displayName = 'PEP';

export default PEP;
